import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PropertyStatus {
  ARREMATADO = 'Arrematado',
  EM_REFORMA = 'Em Reforma',
  A_VENDA = 'À Venda',
  VENDIDO = 'Vendido'
}

export enum PropertyType {
  APARTAMENTO = 'Apartamento',
  CASA = 'Casa',
  TERRENO = 'Terreno',
  COMERCIAL = 'Comercial'
}

export interface MaintenanceCosts {
  condominio: number;
  iptu: number;
  aguaEnergiaPre: number;
  aguaEnergiaPos: number;
}

export interface LegalCosts {
  registroCertidoes: number;
  escritura: number;
  itbi: number;
  taxasRegistro: number;
}

export interface RenovationCosts {
  materiais: number;
  outros: number;
}

export interface SalesCosts {
  impostosVenda: number;
  corretagem: number;
  outrosCustos: number;
}

export interface Property {
  id: string;
  type: PropertyType;
  city: string;
  neighborhood: string;
  address: string;
  sizeM2: number;
  status: PropertyStatus;
  acquisitionDate: string;

  // Entrada
  bankValuation: number;
  acquisitionPrice: number;
  auctioneerCommission: number;

  // Custos
  legal: LegalCosts;
  maintenance: MaintenanceCosts;
  renovation: RenovationCosts;
  sales: SalesCosts;

  // Valor de Venda
  salePrice?: number;
}

export interface PropertyCalculations {
  totalAcquisitionCost: number;
  costPerM2: number;
  totalCost: number;
  realizedProfit: number;
  roi: number;
}

import { Property, PropertyCalculations } from './types';

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(value);
};

export const calculatePropertyMetrics = (p: Property): PropertyCalculations => {
  const legalTotal = p.legal.registroCertidoes + p.legal.escritura + p.legal.itbi + p.legal.taxasRegistro;
  const maintenanceTotal = p.maintenance.condominio + p.maintenance.iptu + p.maintenance.aguaEnergiaPre + p.maintenance.aguaEnergiaPos;
  const renovationTotal = p.renovation.materiais + p.renovation.outros;

  // Custo de aquisição imediato
  const totalAcquisitionCost = p.acquisitionPrice + p.auctioneerCommission + legalTotal;

  // Custo total considerando manutenção e obra
  const operationalTotal = maintenanceTotal + renovationTotal;

  // Custos de venda (ocorrem no momento da venda)
  const salesTotal = p.salePrice ? (p.sales.impostosVenda + p.sales.corretagem + p.sales.outrosCustos) : 0;

  const totalCost = totalAcquisitionCost + operationalTotal + salesTotal;
  const costPerM2 = totalCost / p.sizeM2;

  const realizedProfit = p.salePrice ? (p.salePrice - totalCost) : 0;
  const roi = totalCost > 0 ? (realizedProfit / totalCost) * 100 : 0;

  return {
    totalAcquisitionCost,
    costPerM2,
    totalCost,
    realizedProfit,
    roi
  };
};

