import React, { useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell,
  LineChart,
  Line
} from 'recharts';
import { 
  TrendingUp, 
  DollarSign, 
  Building, 
  Clock, 
  ArrowUpRight, 
  ArrowDownRight 
} from 'lucide-react';
import { Property, PropertyStatus } from '../types';
import { calculatePropertyMetrics, formatCurrency } from '../utils';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'];

const StatCard = ({ title, value, subtitle, icon: Icon, trend }: any) => (
  <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
    <div className="flex items-start justify-between">
      <div>
        <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
        <p className={`text-xs mt-2 flex items-center ${trend >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
          {trend >= 0 ? <ArrowUpRight size={14} className="mr-1" /> : <ArrowDownRight size={14} className="mr-1" />}
          {Math.abs(trend)}% vs mês anterior
        </p>
      </div>
      <div className="p-3 bg-slate-50 rounded-lg text-blue-600">
        <Icon size={24} />
      </div>
    </div>
  </div>
);

const Dashboard = ({ properties }: { properties: Property[] }) => {
  const stats = useMemo(() => {
    const sold = properties.filter(p => p.status === PropertyStatus.VENDIDO);
    const metrics = properties.map(p => calculatePropertyMetrics(p));

    const totalInvested = metrics.reduce((acc, m) => acc + m.totalCost, 0);
    const totalProfit = metrics.reduce((acc, m) => acc + m.realizedProfit, 0);
    const avgROI = sold.length > 0 
      ? metrics.filter((_, i) => properties[i].status === PropertyStatus.VENDIDO)
          .reduce((acc, m) => acc + m.roi, 0) / sold.length 
      : 0;

    const statusCounts = Object.values(PropertyStatus).map(status => ({
      name: status,
      value: properties.filter(p => p.status === status).length
    }));

    const cityROI = Array.from(new Set(properties.map(p => p.city))).map(city => {
      const cityProps = properties.filter(p => p.city === city && p.status === PropertyStatus.VENDIDO);
      const roi = cityProps.length > 0 
        ? cityProps.reduce((acc, p) => acc + calculatePropertyMetrics(p).roi, 0) / cityProps.length
        : 0;
      return { name: city, roi };
    });

    return {
      totalInvested,
      totalProfit,
      avgROI,
      activeProjects: properties.filter(p => p.status !== PropertyStatus.VENDIDO).length,
      statusData: statusCounts,
      cityROI: cityROI.sort((a, b) => b.roi - a.roi)
    };
  }, [properties]);

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Dashboard Executivo</h2>
        <p className="text-slate-500">Visão geral do portfólio Master Imóveis Ltda.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Capital Alocado" 
          value={formatCurrency(stats.totalInvested)} 
          icon={DollarSign} 
          trend={12} 
        />
        <StatCard 
          title="Lucro Realizado" 
          value={formatCurrency(stats.totalProfit)} 
          icon={TrendingUp} 
          trend={8.4} 
        />
        <StatCard 
          title="ROI Médio (Vendas)" 
          value={`${stats.avgROI.toFixed(1)}%`} 
          icon={ArrowUpRight} 
          trend={3.2} 
        />
        <StatCard 
          title="Projetos Ativos" 
          value={stats.activeProjects.toString()} 
          icon={Building} 
          trend={-2} 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* ROI por Cidade */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold mb-6 text-slate-800">ROI Médio Realizado por Cidade</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.cityROI}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis unit="%" />
                <Tooltip 
                  formatter={(value: number) => [`${value.toFixed(2)}%`, 'ROI']}
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="roi" fill="#3b82f6" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Status Distribuição */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold mb-6 text-slate-800">Status do Portfólio</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.statusData}
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {stats.statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center flex-wrap gap-4 mt-4">
            {stats.statusData.map((s, i) => (
              <div key={s.name} className="flex items-center space-x-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                <span className="text-sm text-slate-600">{s.name}: {s.value}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Tabela de Projetos em Destaque */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
          <h3 className="text-lg font-semibold text-slate-800">Desempenho por Imóvel</h3>
          <button className="text-sm text-blue-600 font-medium hover:underline">Ver todos</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-sm uppercase font-semibold">
              <tr>
                <th className="px-6 py-4">Imóvel</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Custo Total</th>
                <th className="px-6 py-4">Preço Venda</th>
                <th className="px-6 py-4">ROI</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {properties.slice(0, 5).map(p => {
                const metrics = calculatePropertyMetrics(p);
                return (
                  <tr key={p.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="font-medium text-slate-900">{p.neighborhood}</div>
                      <div className="text-sm text-slate-500">{p.city} - {p.sizeM2}m²</div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                        p.status === PropertyStatus.VENDIDO ? 'bg-emerald-100 text-emerald-700' :
                        p.status === PropertyStatus.EM_REFORMA ? 'bg-amber-100 text-amber-700' :
                        'bg-blue-100 text-blue-700'
                      }`}>
                        {p.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-700">{formatCurrency(metrics.totalCost)}</td>
                    <td className="px-6 py-4 font-medium text-slate-700">{p.salePrice ? formatCurrency(p.salePrice) : '-'}</td>
                    <td className="px-6 py-4">
                      <span className={`font-bold ${metrics.roi >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {metrics.roi.toFixed(1)}%
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { Search, Filter, Edit2, Trash2, MapPin, Square, MoreHorizontal } from 'lucide-react';
import { Property, PropertyStatus } from '../types';
import { formatCurrency, calculatePropertyMetrics } from '../utils';

interface PropertyListProps {
  properties: Property[];
  onDelete: (id: string) => void;
}

const PropertyList = ({ properties, onDelete }: PropertyListProps) => {
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<PropertyStatus | 'All'>('All');

  const filteredProperties = useMemo(() => {
    return properties.filter(p => {
      const matchesSearch = 
        p.neighborhood.toLowerCase().includes(search.toLowerCase()) || 
        p.city.toLowerCase().includes(search.toLowerCase()) ||
        p.address.toLowerCase().includes(search.toLowerCase());
      const matchesStatus = statusFilter === 'All' || p.status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [properties, search, statusFilter]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Gestão de Imóveis</h2>
          <p className="text-slate-500">Acompanhe todos os ativos do portfólio.</p>
        </div>
        <Link 
          to="/novo" 
          className="bg-blue-600 text-white px-4 py-2 rounded-lg font-semibold hover:bg-blue-700 transition-colors flex items-center justify-center space-x-2"
        >
          <span>Novo Imóvel</span>
        </Link>
      </div>

      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 items-center">
        <div className="relative flex-1 w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por bairro, cidade ou endereço..." 
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="flex items-center space-x-2 w-full md:w-auto">
          <Filter className="text-slate-400" size={18} />
          <select 
            className="border border-slate-200 rounded-lg py-2 px-3 outline-none focus:ring-2 focus:ring-blue-500 w-full"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value as any)}
          >
            <option value="All">Todos os Status</option>
            {Object.values(PropertyStatus).map(s => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredProperties.map(p => {
          const metrics = calculatePropertyMetrics(p);
          return (
            <div key={p.id} className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden flex flex-col hover:shadow-md transition-shadow">
              <div className="relative h-48 bg-slate-200">
                <img 
                  src={`https://picsum.photos/seed/${p.id}/400/300`} 
                  alt={p.neighborhood} 
                  className="w-full h-full object-cover"
                />
                <div className="absolute top-4 left-4">
                  <span className={`px-2 py-1 rounded-lg text-xs font-bold uppercase tracking-wider ${
                    p.status === PropertyStatus.VENDIDO ? 'bg-emerald-500 text-white' :
                    p.status === PropertyStatus.EM_REFORMA ? 'bg-amber-500 text-white' :
                    'bg-blue-500 text-white'
                  }`}>
                    {p.status}
                  </span>
                </div>
              </div>
              <div className="p-6 flex-1 flex flex-col">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="text-lg font-bold text-slate-900 leading-tight">{p.neighborhood}</h3>
                  <p className="text-lg font-bold text-blue-600">{formatCurrency(p.acquisitionPrice)}</p>
                </div>

                <div className="space-y-2 mb-6">
                  <div className="flex items-center text-slate-500 text-sm">
                    <MapPin size={14} className="mr-1" />
                    {p.city} - {p.address}
                  </div>
                  <div className="flex items-center text-slate-500 text-sm">
                    <Square size={14} className="mr-1" />
                    {p.sizeM2} m² • {formatCurrency(metrics.costPerM2)}/m²
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-100 mt-auto">
                  <div>
                    <p className="text-[10px] uppercase font-bold text-slate-400">Investimento</p>
                    <p className="text-sm font-semibold text-slate-700">{formatCurrency(metrics.totalCost)}</p>
                  </div>
                  <div>
                    <p className="text-[10px] uppercase font-bold text-slate-400">ROI Atual</p>
                    <p className={`text-sm font-bold ${metrics.roi >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {metrics.roi.toFixed(1)}%
                    </p>
                  </div>
                </div>

                <div className="flex items-center justify-between mt-6 pt-4 border-t border-slate-100">
                  <Link 
                    to={`/editar/${p.id}`} 
                    className="flex items-center space-x-1 text-slate-600 hover:text-blue-600 font-medium transition-colors"
                  >
                    <Edit2 size={16} />
                    <span>Editar</span>
                  </Link>
                  <button 
                    onClick={() => onDelete(p.id)}
                    className="flex items-center space-x-1 text-slate-400 hover:text-rose-600 transition-colors"
                  >
                    <Trash2 size={16} />
                    <span>Excluir</span>
                  </button>
                </div>
              </div>
            </div>
          );
        })}

        {filteredProperties.length === 0 && (
          <div className="col-span-full py-12 flex flex-col items-center justify-center text-slate-400 bg-white rounded-xl border border-dashed border-slate-300">
            <Building size={48} className="mb-4 opacity-20" />
            <p className="text-lg">Nenhum imóvel encontrado.</p>
          </div>
        )}
      </div>
    </div>
  );
