import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, X, AlertCircle, Info } from 'lucide-react';
import { Property, PropertyStatus, PropertyType } from '../types';

interface PropertyFormProps {
  properties?: Property[];
  onSave: (p: Property) => void;
}

const PropertyForm = ({ properties, onSave }: PropertyFormProps) => {
  const navigate = useNavigate();
  const { id } = useParams();

  const [formData, setFormData] = useState<Partial<Property>>({
    status: PropertyStatus.ARREMATADO,
    type: PropertyType.APARTAMENTO,
    legal: { registroCertidoes: 0, escritura: 0, itbi: 0, taxasRegistro: 0 },
    maintenance: { condominio: 0, iptu: 0, aguaEnergiaPre: 0, aguaEnergiaPos: 0 },
    renovation: { materiais: 0, outros: 0 },
    sales: { impostosVenda: 0, corretagem: 0, outrosCustos: 0 }
  });

  const [errors, setErrors] = useState<string[]>([]);

  useEffect(() => {
    if (id && properties) {
      const existing = properties.find(p => p.id === id);
      if (existing) setFormData(existing);
    }
  }, [id, properties]);

  const handleChange = (path: string, value: any) => {
    const parts = path.split('.');
    if (parts.length === 1) {
      setFormData(prev => ({ ...prev, [path]: value }));
    } else {
      setFormData((prev: any) => ({
        ...prev,
        [parts[0]]: {
          ...prev[parts[0]],
          [parts[1]]: value
        }
      }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: string[] = [];

    // Requisito: Bloquear 'Vendido' sem ITBI e Registro
    if (formData.status === PropertyStatus.VENDIDO) {
      if (!formData.legal?.itbi || formData.legal.itbi <= 0) {
        newErrors.push('Imóveis vendidos devem ter o valor de ITBI preenchido.');
      }
      if (!formData.legal?.taxasRegistro || formData.legal.taxasRegistro <= 0) {
        newErrors.push('Imóveis vendidos devem ter as Taxas de Registro preenchidas.');
      }
      if (!formData.salePrice || formData.salePrice <= 0) {
        newErrors.push('Informe o preço de venda realizado.');
      }
    }

    if (newErrors.length > 0) {
      setErrors(newErrors);
      window.scrollTo(0, 0);
      return;
    }

    const finalData = {
      ...formData,
      id: formData.id || Math.random().toString(36).substr(2, 9),
      acquisitionDate: formData.acquisitionDate || new Date().toISOString().split('T')[0]
    } as Property;

    onSave(finalData);
    navigate('/imoveis');
  };

  const InputField = ({ label, path, type = 'number', prefix }: any) => {
    const parts = path.split('.');
    const value = parts.length === 1 ? (formData as any)[path] : (formData as any)[parts[0]][parts[1]];

    return (
      <div>
        <label className="block text-sm font-medium text-slate-700 mb-1">{label}</label>
        <div className="relative">
          {prefix && <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">{prefix}</span>}
          <input 
            type={type} 
            className={`w-full ${prefix ? 'pl-10' : 'px-3'} py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 transition-shadow`}
            value={value || ''}
            onChange={(e) => handleChange(path, type === 'number' ? parseFloat(e.target.value) : e.target.value)}
          />
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">
            {id ? 'Editar Ativo' : 'Cadastro de Novo Ativo'}
          </h2>
          <p className="text-slate-500">Preencha os detalhes técnicos e financeiros do imóvel.</p>
        </div>
        <button 
          onClick={() => navigate(-1)}
          className="text-slate-400 hover:text-slate-600 transition-colors"
        >
          <X size={24} />
        </button>
      </div>

      {errors.length > 0 && (
        <div className="bg-rose-50 border-l-4 border-rose-500 p-4 rounded-r-lg flex items-start space-x-3">
          <AlertCircle className="text-rose-500 shrink-0" size={20} />
          <div>
            <h4 className="text-rose-800 font-bold text-sm">Erros encontrados:</h4>
            <ul className="list-disc list-inside text-rose-700 text-sm mt-1">
              {errors.map((err, i) => <li key={i}>{err}</li>)}
            </ul>
          </div>
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-8">
        {/* Identificação Básica */}
        <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
          <div className="flex items-center space-x-2 text-blue-600 mb-4">
            <Info size={20} />
            <h3 className="font-bold uppercase tracking-wider text-xs">Identificação e Status</h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tipo de Imóvel</label>
              <select 
                className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                value={formData.type}
                onChange={(e) => handleChange('type', e.target.value)}
              >
                {Object.values(PropertyType).map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Status Atual</label>
              <select 
                className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                value={formData.status}
                onChange={(e) => handleChange('status', e.target.value)}
              >
                {Object.values(PropertyStatus).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <InputField label="Cidade" path="city" type="text" />
            <InputField label="Bairro/Condomínio" path="neighborhood" type="text" />
            <div className="md:col-span-2">
              <InputField label="Endereço Completo" path="address" type="text" />
            </div>
            <InputField label="Tamanho Privativo (m²)" path="sizeM2" />
            <InputField label="Data de Aquisição" path="acquisitionDate" type="date" />
          </div>
        </section>

        {/* Valores de Entrada */}
        <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
          <div className="flex items-center space-x-2 text-blue-600 mb-4">
            <Info size={20} />
            <h3 className="font-bold uppercase tracking-wider text-xs">Valores de Arrematação</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <InputField label="Avaliação Banco" path="bankValuation" prefix="R$" />
            <InputField label="Preço de Aquisição" path="acquisitionPrice" prefix="R$" />
            <InputField label="Comissão Leiloeiro" path="auctioneerCommission" prefix="R$" />
          </div>
        </section>

        {/* Custos Operacionais / Legal */}
        <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
          <div className="flex items-center space-x-2 text-blue-600 mb-4">
            <Info size={20} />
            <h3 className="font-bold uppercase tracking-wider text-xs">Custos Legais e Registro</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <InputField label="Despesas Registro/Certidões" path="legal.registroCertidoes" prefix="R$" />
            <InputField label="Escritura" path="legal.escritura" prefix="R$" />
            <InputField label="ITBI" path="legal.itbi" prefix="R$" />
            <InputField label="Taxas de Registro" path="legal.taxasRegistro" prefix="R$" />
          </div>
        </section>

        {/* Manutenção e Reforma */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
            <h3 className="font-bold uppercase tracking-wider text-xs text-blue-600 mb-4">Manutenção</h3>
            <div className="space-y-4">
              <InputField label="Condomínio" path="maintenance.condominio" prefix="R$" />
              <InputField label="IPTU" path="maintenance.iptu" prefix="R$" />
              <InputField label="Luz/Água (Pré-Posse)" path="maintenance.aguaEnergiaPre" prefix="R$" />
              <InputField label="Luz/Água (Pós-Posse)" path="maintenance.aguaEnergiaPos" prefix="R$" />
            </div>
          </section>

          <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
            <h3 className="font-bold uppercase tracking-wider text-xs text-blue-600 mb-4">Obra / Reforma</h3>
            <div className="space-y-4">
              <InputField label="Materiais e Mão de Obra" path="renovation.materiais" prefix="R$" />
              <InputField label="Outros Custos Obra" path="renovation.outros" prefix="R$" />
            </div>
          </section>
        </div>

        {/* Venda */}
        <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-6">
          <h3 className="font-bold uppercase tracking-wider text-xs text-blue-600 mb-4">Finalização e Venda</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <InputField label="Preço de Venda Realizado" path="salePrice" prefix="R$" />
            <InputField label="Impostos sobre Venda" path="sales.impostosVenda" prefix="R$" />
            <InputField label="Corretagem" path="sales.corretagem" prefix="R$" />
            <InputField label="Outras Despesas Comerciais" path="sales.outrosCustos" prefix="R$" />
          </div>
        </section>

        <div className="flex justify-end pt-6">
          <button 
            type="submit"
            className="bg-blue-600 text-white px-8 py-3 rounded-lg font-bold shadow-lg hover:bg-blue-700 transition-all flex items-center space-x-2"
          >
            <Save size={20} />
            <span>Salvar Ativo</span>
          </button>
        </div>
      </form>
    </div>
  );
};

