  ARREMATADO = 'Arrematado',
  EM_REFORMA = 'Em Reforma',
  A_VENDA = 'À Venda',
  VENDIDO = 'Vendido'
}

export enum PropertyType {
  APARTAMENTO = 'Apartamento',
  CASA = 'Casa',
  TERRENO = 'Terreno',
  COMERCIAL = 'Comercial'
}

export enum ExpenseCategory {
  REFORMA = 'Reforma',
  MANUTENCAO = 'Manutenção',
  IMPOSTOS = 'Impostos',
  LEGAL = 'Legal',
  COMERCIAL = 'Comercial',
  OUTROS = 'Outros'
}

export interface Attachment {
  id: string;
  name: string;
  type: 'image' | 'document';
  url: string;
  date: string;
}

export interface Expense {
  id: string;
  propertyId: string;
  category: ExpenseCategory;
  description: string;
  amount: number;
  date: string;
  userId: string;
  userName: string;
  attachments: Attachment[];
}

export interface User {
  id: string;
  name: string;
  role: string;
}

export interface Property {
  id: string;
  type: PropertyType;
  city: string;
  neighborhood: string;
  address: string;
  sizeM2: number;
  status: PropertyStatus;
  acquisitionDate: string;
  bankValuation: number;
  acquisitionPrice: number;
  auctioneerCommission: number;
  salePrice?: number;
}

export interface PropertyCalculations {
  totalInvested: number;
  costPerM2: number;
  realizedProfit: number;
  roi: number;
  categoryBreakdown: Record<ExpenseCategory, number>;
}

import { Property, PropertyCalculations, Expense, ExpenseCategory } from './types';

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(value);
};

export const calculatePropertyMetrics = (p: Property, expenses: Expense[]): PropertyCalculations => {
  const propertyExpenses = expenses.filter(e => e.propertyId === p.id);

  const categoryBreakdown: Record<ExpenseCategory, number> = {
    [ExpenseCategory.REFORMA]: 0,
    [ExpenseCategory.MANUTENCAO]: 0,
    [ExpenseCategory.IMPOSTOS]: 0,
    [ExpenseCategory.LEGAL]: 0,
    [ExpenseCategory.COMERCIAL]: 0,
    [ExpenseCategory.OUTROS]: 0,
  };

  propertyExpenses.forEach(e => {
    categoryBreakdown[e.category] += e.amount;
  });

  // Investimento inicial fixo
  const initialInvestment = p.acquisitionPrice + p.auctioneerCommission;

  // Total investido (Inicial + Despesas acumuladas)
  const totalInvested = initialInvestment + propertyExpenses.reduce((acc, e) => acc + e.amount, 0);

  const costPerM2 = totalInvested / p.sizeM2;
  const realizedProfit = p.salePrice ? (p.salePrice - totalInvested) : 0;
  const roi = totalInvested > 0 ? (realizedProfit / totalInvested) * 100 : 0;

  return {
    totalInvested,
    costPerM2,
    realizedProfit,
    roi,
    categoryBreakdown
  };
};

