import { Property, PropertyStatus, Expense } from '../types';
import { calculatePropertyMetrics, formatCurrency } from '../utils';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#64748b'];

const StatCard = ({ title, value, icon: Icon, trend }: any) => (
  <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
    <div className="flex items-start justify-between">
      <div>
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
        {trend !== undefined && (
          <p className={`text-xs mt-2 flex items-center ${trend >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
            {trend >= 0 ? <ArrowUpRight size={14} className="mr-1" /> : <ArrowDownRight size={14} className="mr-1" />}
            {Math.abs(trend)}% vs anterior
          </p>
        )}
      </div>
      <div className="p-3 bg-blue-50 rounded-lg text-blue-600">
        <Icon size={20} />
      </div>
    </div>
  </div>
);

const Dashboard = ({ properties, expenses }: { properties: Property[], expenses: Expense[] }) => {
  const stats = useMemo(() => {
    const sold = properties.filter(p => p.status === PropertyStatus.VENDIDO);
    const metrics = properties.map(p => calculatePropertyMetrics(p, expenses));

    const totalInvested = metrics.reduce((acc, m) => acc + m.totalInvested, 0);
    const totalProfit = metrics.reduce((acc, m) => acc + m.realizedProfit, 0);
    const avgROI = sold.length > 0 
      ? metrics.filter((_, i) => properties[i].status === PropertyStatus.VENDIDO)
          .reduce((acc, m) => acc + m.roi, 0) / sold.length 
      : 0;

    const statusCounts = Object.values(PropertyStatus).map(status => ({
      name: status,
      value: properties.filter(p => p.status === status).length
    }));

    const cityROI = Array.from(new Set(properties.map(p => p.city))).map(city => {
      const cityProps = properties.filter(p => p.city === city && p.status === PropertyStatus.VENDIDO);
      const roi = cityProps.length > 0 
        ? cityProps.reduce((acc, p) => acc + calculatePropertyMetrics(p, expenses).roi, 0) / cityProps.length
        : 0;
      return { name: city, roi };
    });

    return {
      totalInvested,
      totalProfit,
      avgROI,
      activeProjects: properties.filter(p => p.status !== PropertyStatus.VENDIDO).length,
      statusData: statusCounts,
      cityROI: cityROI.sort((a, b) => b.roi - a.roi)
    };
  }, [properties, expenses]);

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Performance Financeira</h2>
          <p className="text-slate-500 font-medium">Consolidação de arremates, obras e revendas.</p>
        </div>
        <div className="mt-4 md:mt-0 flex items-center space-x-2 text-sm text-slate-500 bg-white px-3 py-1.5 rounded-full border border-slate-200">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          <span>Dados em tempo real</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Capital Alocado" value={formatCurrency(stats.totalInvested)} icon={DollarSign} trend={12} />
        <StatCard title="Lucro Realizado" value={formatCurrency(stats.totalProfit)} icon={TrendingUp} trend={8} />
        <StatCard title="ROI Médio Vendas" value={`${stats.avgROI.toFixed(1)}%`} icon={ArrowUpRight} trend={3} />
        <StatCard title="Projetos Ativos" value={stats.activeProjects.toString()} icon={Building} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold uppercase tracking-widest text-slate-400 mb-8">ROI por Localidade</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.cityROI}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} unit="%" />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                  formatter={(value: number) => [`${value.toFixed(2)}%`, 'ROI']}
                />
                <Bar dataKey="roi" fill="#3b82f6" radius={[6, 6, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold uppercase tracking-widest text-slate-400 mb-8">Status da Operação</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.statusData}
                  innerRadius={80}
                  outerRadius={110}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {stats.statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} strokeWidth={0} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="grid grid-cols-2 gap-4 mt-4">
            {stats.statusData.map((s, i) => (
              <div key={s.name} className="flex items-center space-x-2 text-xs">
                <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                <span className="text-slate-500 font-medium">{s.name}:</span>
                <span className="text-slate-900 font-bold">{s.value}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Search, Filter, MapPin, Square, Building, ChevronRight } from 'lucide-react';
import { Property, PropertyStatus, Expense } from '../types';
import { formatCurrency, calculatePropertyMetrics } from '../utils';

interface PropertyListProps {
  properties: Property[];
  expenses: Expense[];
  onDelete: (id: string) => void;
}

const PropertyList = ({ properties, expenses, onDelete }: PropertyListProps) => {
  const navigate = useNavigate();
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<PropertyStatus | 'All'>('All');
  const [cityFilter, setCityFilter] = useState<string | 'All'>('All');

  const uniqueCities = useMemo(() => {
    const cities = properties.map(p => p.city);
    return Array.from(new Set(cities)).sort();
  }, [properties]);

  const filteredProperties = useMemo(() => {
    return properties.filter(p => {
      const matchesSearch = 
        p.neighborhood.toLowerCase().includes(search.toLowerCase()) || 
        p.city.toLowerCase().includes(search.toLowerCase()) ||
        p.address.toLowerCase().includes(search.toLowerCase());
      const matchesStatus = statusFilter === 'All' || p.status === statusFilter;
      const matchesCity = cityFilter === 'All' || p.city === cityFilter;
      return matchesSearch && matchesStatus && matchesCity;
    });
  }, [properties, search, statusFilter, cityFilter]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Imóveis</h2>
          <p className="text-slate-500 font-medium">Gestão de ativos e fluxo de caixa.</p>
        </div>
        <Link 
          to="/novo" 
          className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-bold hover:bg-blue-700 transition-all flex items-center justify-center space-x-2 shadow-lg shadow-blue-500/20"
        >
          <Building size={18} />
          <span>Novo Ativo</span>
        </Link>
      </div>

      <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 items-center">
        <div className="relative flex-1 w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por bairro, cidade..." 
            className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <select 
            className="bg-slate-50 border-none rounded-xl py-3 px-4 text-sm font-medium focus:ring-2 focus:ring-blue-500"
            value={cityFilter}
            onChange={(e) => setCityFilter(e.target.value)}
          >
            <option value="All">Cidades</option>
            {uniqueCities.map(city => <option key={city} value={city}>{city}</option>)}
          </select>
          <select 
            className="bg-slate-50 border-none rounded-xl py-3 px-4 text-sm font-medium focus:ring-2 focus:ring-blue-500"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value as any)}
          >
            <option value="All">Status</option>
            {Object.values(PropertyStatus).map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
        {filteredProperties.map(p => {
          const metrics = calculatePropertyMetrics(p, expenses);
          return (
            <div 
              key={p.id} 
              onClick={() => navigate(`/imovel/${p.id}`)}
              className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col hover:shadow-xl hover:-translate-y-1 transition-all cursor-pointer group"
            >
              <div className="relative h-56 bg-slate-200">
                <img 
                  src={`https://picsum.photos/seed/${p.id}/600/400`} 
                  alt={p.neighborhood} 
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                />
                <div className="absolute top-4 left-4">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                    p.status === PropertyStatus.VENDIDO ? 'bg-emerald-500 text-white' :
                    p.status === PropertyStatus.EM_REFORMA ? 'bg-amber-500 text-white' :
                    'bg-blue-600 text-white'
                  }`}>
                    {p.status}
                  </span>
                </div>
              </div>
              <div className="p-6 flex-1 flex flex-col">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h3 className="text-lg font-bold text-slate-900 mb-1">{p.neighborhood}</h3>
                    <div className="flex items-center text-slate-500 text-xs">
                      <MapPin size={12} className="mr-1" /> {p.city}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-xs font-bold text-slate-400 uppercase">Investido</p>
                    <p className="text-sm font-bold text-blue-600">{formatCurrency(metrics.totalInvested)}</p>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4 py-4 border-t border-slate-100">
                  <div>
                    <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Área</p>
                    <p className="text-sm font-bold text-slate-700">{p.sizeM2} m²</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">ROI Atual</p>
                    <p className={`text-sm font-black ${metrics.roi >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                      {metrics.roi.toFixed(1)}%
                    </p>
                  </div>
                </div>

                <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-100 group-hover:text-blue-600 transition-colors">
                  <span className="text-xs font-bold uppercase tracking-widest">Ver Detalhes Financeiros</span>
                  <ChevronRight size={16} />
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PropertyList;

import React, { useState, useMemo } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { 
  ArrowLeft, 
  Calendar, 
  Plus, 
  FileText, 
  Image as ImageIcon, 
  Trash2, 
  ChevronRight, 
  Filter,
  DollarSign,
  TrendingUp,
  MapPin,
  Clock
} from 'lucide-react';
import { Property, Expense, ExpenseCategory, PropertyStatus } from '../types';
import { calculatePropertyMetrics, formatCurrency } from '../utils';

interface PropertyDetailsProps {
  properties: Property[];
  expenses: Expense[];
  onAddExpense: (e: Expense) => void;
  onDeleteExpense: (id: string) => void;
}

const PropertyDetails = ({ properties, expenses, onAddExpense, onDeleteExpense }: PropertyDetailsProps) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'financeiro' | 'despesas' | 'arquivos'>('financeiro');
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);

  // Filtros de despesa
  const [dateFilter, setDateFilter] = useState('');
  const [catFilter, setCatFilter] = useState<ExpenseCategory | 'All'>('All');

  const property = properties.find(p => p.id === id);
  const propertyExpenses = expenses.filter(e => e.propertyId === id);

  const metrics = useMemo(() => 
    property ? calculatePropertyMetrics(property, propertyExpenses) : null
  , [property, propertyExpenses]);

  const filteredExpenses = useMemo(() => {
    return propertyExpenses.filter(e => {
      const matchesDate = !dateFilter || e.date.includes(dateFilter);
      const matchesCat = catFilter === 'All' || e.category === catFilter;
      return matchesDate && matchesCat;
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [propertyExpenses, dateFilter, catFilter]);

  if (!property || !metrics) return <div>Imóvel não encontrado.</div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button onClick={() => navigate('/imoveis')} className="p-2 hover:bg-white rounded-full border border-transparent hover:border-slate-200 transition-all">
            <ArrowLeft size={24} />
          </button>
          <div>
            <h2 className="text-2xl font-bold text-slate-900">{property.neighborhood}</h2>
            <div className="flex items-center text-slate-500 text-sm">
              <MapPin size={14} className="mr-1" /> {property.city} - {property.address}
            </div>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${
            property.status === PropertyStatus.VENDIDO ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'
          }`}>
            {property.status}
          </span>
          <Link to={`/editar/${property.id}`} className="px-4 py-2 border border-slate-200 rounded-lg text-sm font-medium hover:bg-white transition-colors">
            Editar Dados Base
          </Link>
        </div>
      </div>

      {/* Quick Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <p className="text-xs font-bold text-slate-400 uppercase mb-1">Total Investido</p>
          <p className="text-2xl font-bold text-slate-900">{formatCurrency(metrics.totalInvested)}</p>
        </div>
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <p className="text-xs font-bold text-slate-400 uppercase mb-1">Custo por m²</p>
          <p className="text-2xl font-bold text-slate-900">{formatCurrency(metrics.costPerM2)}</p>
        </div>
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <p className="text-xs font-bold text-slate-400 uppercase mb-1">ROI Previsto/Real</p>
          <p className={`text-2xl font-bold ${metrics.roi >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
            {metrics.roi.toFixed(1)}%
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="flex border-b border-slate-100">
          {(['financeiro', 'despesas', 'arquivos'] as const).map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-8 py-4 text-sm font-bold uppercase tracking-wider transition-all ${
                activeTab === tab ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              {tab}
            </button>
          ))}
        </div>

        <div className="p-8">
          {activeTab === 'financeiro' && (
            <div className="space-y-8">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                <div>
                  <h4 className="text-lg font-bold text-slate-800 mb-6">Distribuição de Gastos</h4>
                  <div className="space-y-4">
                    {Object.entries(metrics.categoryBreakdown).map(([cat, val]) => (
                      <div key={cat}>
                        <div className="flex justify-between text-sm mb-1">
                          <span className="text-slate-600 font-medium">{cat}</span>
                          {/* FIX: Cast 'val' to 'number' to satisfy type requirement for formatCurrency */}
                          <span className="text-slate-900 font-bold">{formatCurrency(val as number)}</span>
                        </div>
                        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
                          <div 
                            className="bg-blue-500 h-full rounded-full" 
                            /* FIX: Cast 'val' to 'number' to allow division in arithmetic operation */
                            style={{ width: `${metrics.totalInvested > 0 ? ((val as number) / metrics.totalInvested) * 100 : 0}%` }}
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
                <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
                  <h4 className="text-sm font-bold text-slate-800 uppercase mb-4">Resumo de Arrematação</h4>
                  <div className="space-y-3">
                    <div className="flex justify-between text-sm">
                      <span className="text-slate-500">Preço Arremate:</span>
                      <span className="text-slate-900 font-semibold">{formatCurrency(property.acquisitionPrice)}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-slate-500">Comissão Leiloeiro (5%):</span>
                      <span className="text-slate-900 font-semibold">{formatCurrency(property.auctioneerCommission)}</span>
                    </div>
                    <div className="pt-3 border-t border-slate-200 flex justify-between text-sm font-bold">
                      <span className="text-slate-800">Investimento Base:</span>
                      <span className="text-blue-600">{formatCurrency(property.acquisitionPrice + property.auctioneerCommission)}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'despesas' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-slate-50 p-4 rounded-lg">
                <div className="flex items-center gap-3">
                  <div className="flex items-center space-x-2">
                    <Calendar size={16} className="text-slate-400" />
                    <input 
                      type="month" 
                      className="text-sm border-none bg-transparent focus:ring-0 outline-none"
                      value={dateFilter}
                      onChange={(e) => setDateFilter(e.target.value)}
                    />
                  </div>
                  <div className="w-px h-6 bg-slate-200" />
                  <select 
                    className="text-sm bg-transparent border-none focus:ring-0 outline-none font-medium"
                    value={catFilter}
                    onChange={(e) => setCatFilter(e.target.value as any)}
                  >
                    <option value="All">Todas Categorias</option>
                    {Object.values(ExpenseCategory).map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <button 
                  onClick={() => setIsExpenseModalOpen(true)}
                  className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-md"
                >
                  <Plus size={16} /> Lançar Despesa
                </button>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="text-xs font-bold text-slate-400 uppercase border-b border-slate-100">
                      <th className="py-4 px-2">Data</th>
                      <th className="py-4 px-2">Categoria</th>
                      <th className="py-4 px-2">Descrição</th>
                      <th className="py-4 px-2">Responsável</th>
                      <th className="py-4 px-2 text-right">Valor</th>
                      <th className="py-4 px-2"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {filteredExpenses.map((exp) => (
                      <tr key={exp.id} className="group hover:bg-slate-50 transition-colors">
                        <td className="py-4 px-2 text-sm text-slate-500">{new Date(exp.date).toLocaleDateString('pt-BR')}</td>
                        <td className="py-4 px-2">
                          <span className="text-[10px] font-bold uppercase px-2 py-1 bg-slate-100 rounded-md text-slate-600">
                            {exp.category}
                          </span>
                        </td>
                        <td className="py-4 px-2 text-sm font-medium text-slate-800">{exp.description}</td>
                        <td className="py-4 px-2">
                          <div className="flex items-center space-x-2">
                            <div className="w-6 h-6 rounded-full bg-blue-100 flex items-center justify-center text-[10px] font-bold text-blue-600 uppercase">
                              {exp.userName.split(' ').map(n => n[0]).join('')}
                            </div>
                            <span className="text-xs text-slate-500">{exp.userName}</span>
                          </div>
                        </td>
                        <td className="py-4 px-2 text-sm font-bold text-slate-900 text-right">{formatCurrency(exp.amount)}</td>
                        <td className="py-4 px-2 text-right">
                          <button 
                            onClick={() => onDeleteExpense(exp.id)}
                            className="p-2 text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"
                          >
                            <Trash2 size={16} />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {filteredExpenses.length === 0 && (
                      <tr>
                        <td colSpan={6} className="py-12 text-center text-slate-400 text-sm italic">
                          Nenhum lançamento encontrado para este filtro.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'arquivos' && (
            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
              <label className="border-2 border-dashed border-slate-200 rounded-xl p-8 flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <Plus size={32} className="text-slate-300 group-hover:text-blue-500 mb-2" />
                <span className="text-xs font-bold text-slate-400 group-hover:text-blue-600 uppercase">Anexar</span>
                <input type="file" className="hidden" />
              </label>

              {/* Mock de Arquivos */}
              {[1, 2, 3].map(i => (
