              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Categoria</label>
                <select className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" id="exp_cat">
                  {Object.values(ExpenseCategory).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Descrição</label>
                <input type="text" placeholder="Ex: Pintura sala ou IPTU 2024" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" id="exp_desc" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Valor</label>
                <input type="number" placeholder="0,00" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" id="exp_amount" />
              </div>
            </div>
            <div className="flex gap-4 mt-8">
              <button 
                onClick={() => setIsExpenseModalOpen(false)}
                className="flex-1 py-3 text-sm font-bold text-slate-400 hover:text-slate-600"
              >
                Cancelar
              </button>
              <button 
                onClick={() => {
                  const date = (document.getElementById('exp_date') as HTMLInputElement).value;
                  const cat = (document.getElementById('exp_cat') as HTMLSelectElement).value as ExpenseCategory;
                  const desc = (document.getElementById('exp_desc') as HTMLInputElement).value;
                  const amount = parseFloat((document.getElementById('exp_amount') as HTMLInputElement).value);

                  if (!desc || !amount) return alert('Preencha os campos obrigatórios');

                  onAddExpense({
                    id: Math.random().toString(36).substr(2, 9),
                    propertyId: id!,
                    category: cat,
                    description: desc,
                    amount: amount,
                    date: date,
                    userId: 'u1',
                    userName: 'Carlos Silva',
                    attachments: []
                  });
                  setIsExpenseModalOpen(false);
                }}
                className="flex-1 py-3 bg-blue-600 text-white rounded-xl text-sm font-bold shadow-lg hover:bg-blue-700 transition-all"
              >
                Confirmar Lançamento
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

