const AppContent = () => {
  const [properties, setProperties] = useState<Property[]>(() => {
    const saved = localStorage.getItem('master_imoveis_data');
    return saved ? JSON.parse(saved) : INITIAL_PROPERTIES;
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('master_imoveis_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('master_imoveis_inventory');
    return saved ? JSON.parse(saved) : [];
  });

  const [movements, setMovements] = useState<StockMovement[]>(() => {
    const saved = localStorage.getItem('master_imoveis_movements');
    return saved ? JSON.parse(saved) : [];
  });

  const [suppliers, setSuppliers] = useState<Supplier[]>(() => {
    const saved = localStorage.getItem('master_imoveis_suppliers');
    return saved ? JSON.parse(saved) : [];
  });

  const [warehouses, setWarehouses] = useState<Warehouse[]>(() => {
    const saved = localStorage.getItem('master_imoveis_warehouses');
    return saved ? JSON.parse(saved) : [{ id: 'w1', name: 'Almoxarifado Central', location: 'Matriz' }];
  });

  const location = useLocation();

  useEffect(() => {
    localStorage.setItem('master_imoveis_data', JSON.stringify(properties));
    localStorage.setItem('master_imoveis_expenses', JSON.stringify(expenses));
    localStorage.setItem('master_imoveis_inventory', JSON.stringify(inventory));
    localStorage.setItem('master_imoveis_movements', JSON.stringify(movements));
    localStorage.setItem('master_imoveis_suppliers', JSON.stringify(suppliers));
    localStorage.setItem('master_imoveis_warehouses', JSON.stringify(warehouses));
  }, [properties, expenses, inventory, movements, suppliers, warehouses]);

  const addProperty = (p: Property) => setProperties(prev => [...prev, p]);
  const updateProperty = (updated: Property) => setProperties(prev => prev.map(p => p.id === updated.id ? updated : p));
  const addExpense = (e: Expense) => setExpenses(prev => [e, ...prev]);
  const deleteExpense = (id: string) => setExpenses(prev => prev.filter(exp => exp.id !== id));

  const addMovement = (m: StockMovement) => {
    setMovements(prev => [m, ...prev]);
    // Atualiza estoque atual do item
    setInventory(prev => prev.map(item => {
      if (item.id === m.itemId) {
        const factor = (m.type === MovementType.ENTRADA_COMPRA || m.type === MovementType.AJUSTE_INVENTARIO) ? 1 : -1;
        return { ...item, currentStock: item.currentStock + (m.quantity * factor) };
      }
      return item;
    }));

    // Se for entrada por compra vinculada a obra, gera despesa automática
    if (m.type === MovementType.ENTRADA_COMPRA && m.propertyId) {
      const item = inventory.find(i => i.id === m.itemId);
      const supplier = suppliers.find(s => s.id === m.supplierId);
      addExpense({
        id: `exp-mov-${m.id}`,
        propertyId: m.propertyId,
        category: ExpenseCategory.REFORMA,
        description: `Compra: ${item?.name} (${supplier?.name || 'S/ Fornecedor'})`,
        amount: m.totalPrice,
        date: m.date,
        userId: 'system',
        userName: 'Lançamento Automático (Estoque)',
        attachments: []
      });
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 text-white flex flex-col p-6 sticky top-0 h-screen overflow-y-auto z-20">
        <div className="flex items-center space-x-2 mb-10 px-2">
          <div className="bg-blue-600 p-2 rounded-lg">
            <Building2 size={24} />
          </div>
          <div>
            <h1 className="text-lg font-bold leading-none">Master Imóveis</h1>
            <span className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Portal ERP</span>
          </div>
        </div>

        <nav className="flex-1 space-y-2">
          <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} />
          <SidebarItem to="/imoveis" icon={Home} label="Imóveis" active={location.pathname.startsWith('/imoveis') || location.pathname.startsWith('/imovel')} />

          <SidebarGroup label="Estoque" icon={Box} active={location.pathname.startsWith('/estoque')}>
            <SubItem to="/estoque/insumos" label="Insumos" active={location.pathname === '/estoque/insumos'} />
            <SubItem to="/estoque/movimentos" label="Movimentos" active={location.pathname === '/estoque/movimentos'} />
            <SubItem to="/estoque/almoxarifados" label="Almoxarifados" active={location.pathname === '/estoque/almoxarifados'} />
            <SubItem to="/estoque/fornecedores" label="Fornecedores" active={location.pathname === '/estoque/fornecedores'} />
          </SidebarGroup>

          <SidebarItem to="/equipe" icon={Users} label="Equipe" active={location.pathname === '/equipe'} />
        </nav>

        <div className="mt-auto pt-6 border-t border-slate-800 space-y-1">
          <SidebarItem to="/configuracoes" icon={Settings} label="Ajustes" active={location.pathname === '/configuracoes'} />
          <button className="flex items-center space-x-3 p-3 w-full rounded-lg text-slate-400 hover:bg-slate-800 hover:text-white transition-colors">
            <LogOut size={20} />
            <span className="font-medium">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        <Routes>
          <Route path="/" element={<Dashboard properties={properties} expenses={expenses} />} />
          <Route path="/imoveis" element={<PropertyList properties={properties} expenses={expenses} onDelete={() => {}} />} />
          <Route path="/imovel/:id" element={<PropertyDetails properties={properties} expenses={expenses} onAddExpense={addExpense} onDeleteExpense={deleteExpense} />} />
          <Route path="/novo" element={<PropertyForm onSave={addProperty} />} />
          <Route path="/editar/:id" element={<PropertyForm properties={properties} onSave={updateProperty} />} />

          <Route path="/estoque/insumos" element={<InsumosPage items={inventory} setItems={setInventory} />} />
          <Route path="/estoque/movimentos" element={<MovimentosPage movements={movements} items={inventory} properties={properties} suppliers={suppliers} onAddMovement={addMovement} />} />
          <Route path="/estoque/fornecedores" element={<FornecedoresPage suppliers={suppliers} setSuppliers={setSuppliers} />} />
