interface MovimentosPageProps {
  movements: StockMovement[];
  items: InventoryItem[];
  suppliers: Supplier[];
  properties: Property[];
  onAddMovement: (m: StockMovement) => void;
}

const MovimentosPage = ({ movements, items, suppliers, properties, onAddMovement }: MovimentosPageProps) => {
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const form = e.target as HTMLFormElement;

    const qty = parseFloat((form.elements.namedItem('quantity') as HTMLInputElement).value);
    const unitP = parseFloat((form.elements.namedItem('unitPrice') as HTMLInputElement).value);
    const type = (form.elements.namedItem('type') as HTMLSelectElement).value as MovementType;
    const itemId = (form.elements.namedItem('itemId') as HTMLSelectElement).value;

    const newMov: StockMovement = {
      id: Math.random().toString(36).substr(2, 9),
      itemId,
      type,
      quantity: qty,
      unitPrice: unitP,
      totalPrice: qty * unitP,
      date: (form.elements.namedItem('date') as HTMLInputElement).value,
      supplierId: (form.elements.namedItem('supplierId') as HTMLSelectElement).value || undefined,
      propertyId: (form.elements.namedItem('propertyId') as HTMLSelectElement).value || undefined,
      description: (form.elements.namedItem('description') as HTMLInputElement).value,
    };

    onAddMovement(newMov);
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Movimentações</h2>
          <p className="text-slate-500 font-medium">Histórico de compras e consumo nas obras.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg"
        >
          <ShoppingCart size={18} /> Lançar Movimento
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100 text-[10px] font-black uppercase text-slate-400 tracking-widest">
            <tr>
              <th className="px-6 py-4">Data</th>
              <th className="px-6 py-4">Tipo</th>
              <th className="px-6 py-4">Item</th>
              <th className="px-6 py-4">Qtd</th>
              <th className="px-6 py-4">Vlr Unit.</th>
              <th className="px-6 py-4">Origem / Destino</th>
              <th className="px-6 py-4 text-right">Total</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {movements.map((mov) => {
              const item = items.find(i => i.id === mov.itemId);
              const property = properties.find(p => p.id === mov.propertyId);
              return (
                <tr key={mov.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 text-sm text-slate-500">{new Date(mov.date).toLocaleDateString('pt-BR')}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${
                      mov.type === MovementType.ENTRADA_COMPRA ? 'bg-emerald-100 text-emerald-700' : 
                      mov.type === MovementType.SAIDA_OBRA ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-600'
                    }`}>
                      {mov.type}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-800">{item?.name || 'Item Excluído'}</td>
                  <td className="px-6 py-4 text-sm font-medium">{mov.quantity} {item?.unit}</td>
                  <td className="px-6 py-4 text-sm text-slate-500">{formatCurrency(mov.unitPrice)}</td>
                  <td className="px-6 py-4">
                    {mov.propertyId ? (
                      <div className="flex items-center text-xs text-blue-600 font-bold">
                        <MapPin size={12} className="mr-1" /> {property?.neighborhood}
                      </div>
                    ) : (
                      <div className="flex items-center text-xs text-slate-400">
                        <Truck size={12} className="mr-1" /> Almoxarifado
                      </div>
                    )}
                  </td>
                  <td className="px-6 py-4 text-right font-black text-slate-900">{formatCurrency(mov.totalPrice)}</td>
                </tr>
              );
            })}
            {movements.length === 0 && (
              <tr>
                <td colSpan={7} className="py-12 text-center text-slate-400 italic">Nenhuma movimentação registrada.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg p-8">
            <h3 className="text-xl font-bold mb-6">Nova Movimentação</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Tipo</label>
                  <select name="type" required className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500">
                    {Object.values(MovementType).map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Data</label>
                  <input name="date" required type="date" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" defaultValue={new Date().toISOString().split('T')[0]} />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Item / Insumo</label>
                <select name="itemId" required className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500">
                  <option value="">Selecione um item...</option>
                  {items.map(i => <option key={i.id} value={i.id}>{i.name} ({i.unit}) - Estoque: {i.currentStock}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Quantidade</label>
                  <input name="quantity" required type="number" step="0.01" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Preço Unitário</label>
                  <input name="unitPrice" required type="number" step="0.01" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" placeholder="R$" />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Observações / Descrição</label>
                <input name="description" type="text" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" placeholder="Ex: NF 1234 - Pintura sala" />
              </div>

              <div className="grid grid-cols-2 gap-4 pt-2 border-t border-slate-100">
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Vincular à Obra (Opcional)</label>
                  <select name="propertyId" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500">
                    <option value="">Almoxarifado Geral</option>
                    {properties.map(p => <option key={p.id} value={p.id}>{p.neighborhood} ({p.city})</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Fornecedor (Opcional)</label>
                  <select name="supplierId" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500">
                    <option value="">Nenhum</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>
              </div>

              <div className="flex gap-4 mt-8">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 text-sm font-bold text-slate-400">Cancelar</button>
                <button type="submit" className="flex-1 py-3 bg-blue-600 text-white rounded-xl text-sm font-bold shadow-lg hover:bg-blue-700 transition-all">Confirmar Lançamento</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

