    localStorage.setItem('master_imoveis_suppliers', JSON.stringify(suppliers));
    localStorage.setItem('master_imoveis_warehouses', JSON.stringify(warehouses));
    localStorage.setItem('master_imoveis_users', JSON.stringify(users));
    localStorage.setItem('master_imoveis_teams', JSON.stringify(teams));
  }, [properties, expenses, inventory, movements, suppliers, warehouses, users, teams]);

  const addMovement = (m: StockMovement) => {
    setMovements(prev => [m, ...prev]);
    setInventory(prev => prev.map(item => {
      if (item.id === m.itemId) {
        const factor = (m.type === MovementType.ENTRADA_COMPRA || m.type === MovementType.AJUSTE_INVENTARIO) ? 1 : -1;
        return { ...item, currentStock: item.currentStock + (m.quantity * factor) };
      }
      return item;
    }));
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 text-white flex flex-col p-6 sticky top-0 h-screen overflow-y-auto z-20 shadow-2xl">
        <div className="flex items-center space-x-3 mb-10 px-2 group">
          <div className="bg-blue-600 p-2 rounded-xl group-hover:rotate-12 transition-transform">
            <Building2 size={24} />
          </div>
          <div>
            <h1 className="text-lg font-bold leading-none">Master Imóveis</h1>
            <span className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Portal ERP</span>
          </div>
        </div>

        <nav className="flex-1 space-y-2">
          <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} />

          <div className="pt-4 pb-2 px-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider">Gestão Operacional</div>
          <SidebarItem to="/imoveis" icon={Home} label="Imóveis" active={location.pathname.startsWith('/imoveis') || location.pathname.startsWith('/imovel')} />

          <SidebarGroup label="Estoque" icon={Box} active={location.pathname.startsWith('/estoque')}>
            <SubItem to="/estoque/insumos" label="Insumos" active={location.pathname === '/estoque/insumos'} />
            <SubItem to="/estoque/movimentos" label="Movimentos" active={location.pathname === '/estoque/movimentos'} />
            <SubItem to="/estoque/almoxarifados" label="Almoxarifados" active={location.pathname === '/estoque/almoxarifados'} />
            <SubItem to="/estoque/fornecedores" label="Fornecedores" active={location.pathname === '/estoque/fornecedores'} />
          </SidebarGroup>

          <div className="pt-4 pb-2 px-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider">Estratégico</div>
          <SidebarItem to="/relatorios" icon={BarChart3} label="Relatórios" active={location.pathname.startsWith('/relatorios')} />
          <SidebarItem to="/equipe" icon={Users} label="Equipe" active={location.pathname.startsWith('/equipe')} />
        </nav>

        <div className="mt-auto pt-6 border-t border-slate-800 space-y-4">
          <div className="flex items-center space-x-3 px-2 py-3 bg-slate-800/50 rounded-xl">
            <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-xs font-bold">
              {currentUser.name[0]}
            </div>
            <div className="flex-1 overflow-hidden">
              <p className="text-xs font-bold truncate">{currentUser.name}</p>
              <p className="text-[10px] text-slate-400 flex items-center">
                <ShieldCheck size={10} className="mr-1 text-blue-400" /> {currentUser.role}
              </p>
            </div>
          </div>
          <SidebarItem to="/configuracoes" icon={Settings} label="Ajustes" active={location.pathname === '/configuracoes'} />
          <button className="flex items-center space-x-3 p-3 w-full rounded-lg text-rose-400 hover:bg-rose-500/10 transition-colors">
            <LogOut size={20} />
            <span className="font-medium">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        <Routes>
          <Route path="/" element={<Dashboard properties={properties} expenses={expenses} />} />
          <Route path="/imoveis" element={<PropertyList properties={properties} expenses={expenses} onDelete={() => {}} />} />
          <Route path="/imovel/:id" element={<PropertyDetails properties={properties} expenses={expenses} onAddExpense={(e) => setExpenses(prev => [e, ...prev])} onDeleteExpense={(id) => setExpenses(prev => prev.filter(e => e.id !== id))} />} />
          <Route path="/novo" element={<PropertyForm onSave={(p) => setProperties(prev => [...prev, p])} />} />

          <Route path="/estoque/insumos" element={<InsumosPage items={inventory} setItems={setInventory} />} />
          <Route path="/estoque/movimentos" element={<MovimentosPage movements={movements} items={inventory} properties={properties} suppliers={suppliers} onAddMovement={addMovement} />} />
          <Route path="/estoque/fornecedores" element={<FornecedoresPage suppliers={suppliers} setSuppliers={setSuppliers} />} />
          <Route path="/estoque/almoxarifados" element={<AlmoxarifadosPage warehouses={warehouses} setWarehouses={setWarehouses} />} />

          <Route path="/relatorios" element={<ReportsPage properties={properties} expenses={expenses} inventory={inventory} />} />
          <Route path="/equipe" element={<TeamsPage currentUser={currentUser} users={users} setUsers={setUsers} teams={teams} setTeams={setTeams} />} />

          <Route path="/configuracoes" element={<SettingsPage />} />
        </Routes>
      </main>
    </div>
  );
};

const App = () => (
  <HashRouter>
    <AppContent />
  </HashRouter>
);

export default App;

import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  LineChart, Line, Cell, PieChart, Pie 
} from 'recharts';
import { FileDown, TrendingUp, DollarSign, Package, MapPin } from 'lucide-react';
import { Property, Expense, InventoryItem, PropertyStatus } from '../types';
import { calculatePropertyMetrics, formatCurrency } from '../utils';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

const ReportsPage = ({ properties, expenses, inventory }: { properties: Property[], expenses: Expense[], inventory: InventoryItem[] }) => {
  const metrics = useMemo(() => {
    const propertyData = properties.map(p => ({
      ...p,
      metrics: calculatePropertyMetrics(p, expenses)
    }));

    const totalInvested = propertyData.reduce((acc, p) => acc + p.metrics.totalInvested, 0);
    const totalInventoryValue = inventory.reduce((acc, i) => acc + (i.currentStock * 0), 0); // Mock de valor

    const roiByCity = Array.from(new Set(properties.map(p => p.city))).map(city => {
      const cityProps = propertyData.filter(p => p.city === city && p.status === PropertyStatus.VENDIDO);
      return {
        city,
        roi: cityProps.length > 0 ? cityProps.reduce((acc, p) => acc + p.metrics.roi, 0) / cityProps.length : 0
      };
    });

    const statusDist = Object.values(PropertyStatus).map(s => ({
      name: s,
      value: properties.filter(p => p.status === s).length
    }));

    return { totalInvested, roiByCity, statusDist };
  }, [properties, expenses, inventory]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Relatórios Gerenciais</h2>
          <p className="text-slate-500 font-medium">Análise de dados para tomada de decisão.</p>
        </div>
        <button className="flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-xl text-sm font-bold hover:bg-slate-800 transition-all">
          <FileDown size={18} /> Exportar Tudo (PDF)
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Gráfico ROI por Cidade */}
        <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold uppercase text-slate-400 tracking-widest mb-6">Eficiência de Arremate por Praça</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={metrics.roiByCity}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="city" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} unit="%" />
                <Tooltip />
                <Bar dataKey="roi" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Gráfico Distribuição de Status */}
        <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold uppercase text-slate-400 tracking-widest mb-6">Pipeline de Ativos</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={metrics.statusDist} innerRadius={60} outerRadius={80} dataKey="value">
                  {metrics.statusDist.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="grid grid-cols-3 gap-2 mt-4 text-[10px] font-bold uppercase">
            {metrics.statusDist.map((s, i) => (
              <div key={s.name} className="flex items-center gap-1">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }} />
                <span className="text-slate-500 truncate">{s.name}: {s.value}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-blue-600 p-6 rounded-2xl text-white shadow-lg">
          <p className="text-[10px] font-bold uppercase opacity-80 mb-1">Total Imobilizado</p>
          <p className="text-2xl font-black">{formatCurrency(metrics.totalInvested)}</p>
        </div>
        <div className="bg-emerald-600 p-6 rounded-2xl text-white shadow-lg">
          <p className="text-[10px] font-bold uppercase opacity-80 mb-1">Retorno Médio</p>
          <p className="text-2xl font-black">28.4% <span className="text-xs font-normal opacity-70">Líquido</span></p>
        </div>
        <div className="bg-slate-900 p-6 rounded-2xl text-white shadow-lg">
          <p className="text-[10px] font-bold uppercase opacity-80 mb-1">Giro Médio</p>
          <p className="text-2xl font-black">142 <span className="text-xs font-normal opacity-70">Dias</span></p>
        </div>
      </div>
    </div>
  );
};

