        <div className="flex gap-4">
          <button 
            onClick={() => setIsTeamModalOpen(true)}
            className="bg-white text-slate-900 border border-slate-200 px-4 py-2.5 rounded-xl font-bold text-sm hover:bg-slate-50 transition-all flex items-center gap-2"
          >
            <Plus size={18} /> Novo Time
          </button>
          {isMaster && (
            <button 
              onClick={() => setIsUserModalOpen(true)}
              className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-bold text-sm hover:bg-blue-700 transition-all shadow-lg flex items-center gap-2"
