        >
          Colaboradores
        </button>
        <button 
          onClick={() => setActiveTab('teams')}
          className={`px-8 py-4 text-sm font-bold uppercase tracking-wider transition-all ${activeTab === 'teams' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-400'}`}
        >
          Times
        </button>
      </div>

      {activeTab === 'users' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
