import React, { useState, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Search, MapPin, Building, ChevronRight, LayoutGrid, Kanban as KanbanIcon, ArrowRight } from 'lucide-react';
import { Property, PropertyStatus, Expense } from '../types';
import { formatCurrency, calculatePropertyMetrics } from '../utils';

interface PropertyListProps {
  properties: Property[];
  expenses: Expense[];
  onUpdateStatus: (id: string, status: PropertyStatus) => void;
}

const PropertyList = ({ properties, expenses, onUpdateStatus }: PropertyListProps) => {
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<'grid' | 'kanban'>('kanban');
  const [search, setSearch] = useState('');

  const filteredProperties = useMemo(() => {
    return properties.filter(p => 
      p.neighborhood.toLowerCase().includes(search.toLowerCase()) || 
      p.city.toLowerCase().includes(search.toLowerCase())
    );
  }, [properties, search]);

  const onDragStart = (e: React.DragEvent, propertyId: string) => {
    e.dataTransfer.setData('propertyId', propertyId);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const onDrop = (e: React.DragEvent, status: PropertyStatus) => {
    const propertyId = e.dataTransfer.getData('propertyId');
    onUpdateStatus(propertyId, status);
  };

  const KanbanColumn = ({ status, items }: { status: PropertyStatus, items: Property[] }) => (
    <div 
      onDragOver={onDragOver}
      onDrop={(e) => onDrop(e, status)}
      className="flex flex-col min-w-[300px] max-w-[350px] bg-slate-100/50 rounded-2xl p-4 min-h-[600px] border border-dashed border-slate-200"
    >
      <div className="flex items-center justify-between mb-4 px-2">
        <h3 className="text-xs font-black uppercase tracking-widest text-slate-400">{status}</h3>
        <span className="bg-white px-2 py-0.5 rounded-full text-[10px] font-bold text-slate-500 shadow-sm">{items.length}</span>
      </div>

      <div className="space-y-4">
        {items.map(p => {
          const metrics = calculatePropertyMetrics(p, expenses);
          return (
            <div 
              key={p.id}
              draggable
              onDragStart={(e) => onDragStart(e, p.id)}
              onClick={() => navigate(`/imovel/${p.id}`)}
              className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-grab active:cursor-grabbing group"
            >
              <div className="flex justify-between items-start mb-2">
                <h4 className="font-bold text-slate-900 text-sm truncate leading-tight">{p.neighborhood}</h4>
                <div className="flex items-center text-[10px] text-emerald-600 font-bold">
                   {metrics.roi.toFixed(0)}% ROI
                </div>
              </div>
              <p className="text-[10px] text-slate-400 flex items-center mb-3">
                <MapPin size={10} className="mr-1" /> {p.city}
              </p>
              <div className="flex justify-between items-center pt-3 border-t border-slate-50">
                <span className="text-xs font-black text-blue-600">{formatCurrency(metrics.totalInvested)}</span>
                <ChevronRight size={14} className="text-slate-300 group-hover:text-blue-500" />
              </div>
            </div>
          );
        })}
        {items.length === 0 && (
          <div className="flex-1 flex items-center justify-center py-10 text-slate-300 text-[10px] uppercase font-bold text-center italic">
            Arraste um imóvel para esta etapa
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Gestão Visual</h2>
          <p className="text-slate-500 font-medium">Controle de fluxo de vida dos ativos.</p>
        </div>
        <div className="flex items-center gap-3">
           <div className="bg-white border border-slate-200 rounded-xl p-1 flex shadow-sm">
              <button 
                onClick={() => setViewMode('kanban')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'kanban' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <KanbanIcon size={18} />
              </button>
              <button 
                onClick={() => setViewMode('grid')}
                className={`p-2 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <LayoutGrid size={18} />
              </button>
           </div>
           <Link to="/novo" className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-bold hover:bg-blue-700 transition-all flex items-center space-x-2 shadow-lg">
            <Building size={18} /> <span>Novo Ativo</span>
           </Link>
        </div>
      </div>

      <div className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
        <div className="relative w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Filtrar por nome ou cidade..." 
            className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </div>

      {viewMode === 'kanban' ? (
        <div className="flex gap-6 overflow-x-auto pb-8 snap-x">
          <KanbanColumn status={PropertyStatus.ARREMATADO} items={filteredProperties.filter(p => p.status === PropertyStatus.ARREMATADO)} />
          <KanbanColumn status={PropertyStatus.EM_REFORMA} items={filteredProperties.filter(p => p.status === PropertyStatus.EM_REFORMA)} />
          <KanbanColumn status={PropertyStatus.A_VENDA} items={filteredProperties.filter(p => p.status === PropertyStatus.A_VENDA)} />
          <KanbanColumn status={PropertyStatus.VENDIDO} items={filteredProperties.filter(p => p.status === PropertyStatus.VENDIDO)} />
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredProperties.map(p => {
             const metrics = calculatePropertyMetrics(p, expenses);
             return (
              <div key={p.id} onClick={() => navigate(`/imovel/${p.id}`)} className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden hover:shadow-lg transition-all cursor-pointer group">
