                          <p className="font-black text-slate-800">{formatCurrency(metrics.totalInvested)}</p>
                       </div>
                       <ArrowRight size={18} className="text-slate-300 group-hover:text-blue-600 transition-colors" />
                    </div>
                 </div>
              </div>
             );
          })}
        </div>
      )}
    </div>
  );
};

