import React, { useState, useMemo } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { 
  ArrowLeft, 
  Calendar, 
  Plus, 
  Trash2, 
  MapPin,
  History,
  User,
  Clock,
  ArrowRight
} from 'lucide-react';
import { Property, Expense, ExpenseCategory, PropertyStatus, PropertyLog } from '../types';
import { calculatePropertyMetrics, formatCurrency } from '../utils';

interface PropertyDetailsProps {
  properties: Property[];
  expenses: Expense[];
  logs: PropertyLog[];
  onAddExpense: (e: Expense) => void;
  onDeleteExpense: (id: string) => void;
}

const PropertyDetails = ({ properties, expenses, logs, onAddExpense, onDeleteExpense }: PropertyDetailsProps) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'financeiro' | 'despesas' | 'timeline'>('financeiro');
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);

  const property = properties.find(p => p.id === id);
  const propertyExpenses = expenses.filter(e => e.propertyId === id);
  const propertyLogs = logs.filter(l => l.propertyId === id).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

  const metrics = useMemo(() => property ? calculatePropertyMetrics(property, propertyExpenses) : null, [property, propertyExpenses]);

  if (!property || !metrics) return <div className="p-8 text-center text-slate-400">Imóvel não encontrado.</div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button onClick={() => navigate('/imoveis')} className="p-2 hover:bg-white rounded-full border border-transparent hover:border-slate-200 transition-all">
            <ArrowLeft size={24} />
          </button>
          <div>
            <h2 className="text-2xl font-bold text-slate-900">{property.neighborhood}</h2>
            <div className="flex items-center text-slate-500 text-sm">
              <MapPin size={14} className="mr-1" /> {property.city}
            </div>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <span className={`px-4 py-1.5 rounded-xl text-xs font-black uppercase tracking-widest ${
            property.status === PropertyStatus.VENDIDO ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-blue-600 text-white shadow-lg shadow-blue-500/20'
          }`}>
            {property.status}
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Total Investido</p>
          <p className="text-2xl font-black text-slate-900">{formatCurrency(metrics.totalInvested)}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Lucro Estimado</p>
          <p className={`text-2xl font-black ${metrics.realizedProfit >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
            {formatCurrency(metrics.realizedProfit)}
          </p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Retorno (ROI)</p>
          <p className={`text-2xl font-black ${metrics.roi >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
            {metrics.roi.toFixed(1)}%
          </p>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="flex border-b border-slate-100 bg-slate-50/50">
          {(['financeiro', 'despesas', 'timeline'] as const).map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-8 py-4 text-xs font-bold uppercase tracking-widest transition-all ${
                activeTab === tab ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              {tab === 'timeline' && <History size={14} className="inline mr-2" />}
              {tab}
            </button>
          ))}
        </div>

        <div className="p-8">
          {activeTab === 'financeiro' && (
            <div className="space-y-8 animate-in slide-in-from-bottom-2">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                <div className="space-y-6">
                  <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Composição de Custos</h4>
                  <div className="space-y-4">
                    {Object.entries(metrics.categoryBreakdown).map(([cat, val]) => (
                      <div key={cat}>
                        <div className="flex justify-between text-xs font-bold mb-1.5">
                          <span className="text-slate-600 uppercase">{cat}</span>
                          <span className="text-slate-900">{formatCurrency(val as number)}</span>
                        </div>
                        <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                          <div className="bg-blue-600 h-full rounded-full" style={{ width: `${metrics.totalInvested > 0 ? ((val as number) / metrics.totalInvested) * 100 : 0}%` }} />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200">
                  <h4 className="text-xs font-bold text-slate-400 uppercase mb-4 tracking-widest">Detalhes da Transação</h4>
                  <div className="space-y-3">
                    <div className="flex justify-between text-sm">
