                      <span className="text-slate-900 font-black">{formatCurrency(property.auctioneerCommission)}</span>
                    </div>
                    <div className="pt-4 border-t border-slate-200 flex justify-between text-base font-black">
                      <span className="text-slate-800">Custo Arremate:</span>
                      <span className="text-blue-600">{formatCurrency(property.acquisitionPrice + property.auctioneerCommission)}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
