          {activeTab === 'despesas' && (
            <div className="space-y-6 animate-in slide-in-from-bottom-2">
              <div className="flex justify-between items-center">
                <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Lançamentos Financeiros</h4>
                <button 
                  onClick={() => setIsExpenseModalOpen(true)}
                  className="bg-blue-600 text-white px-4 py-2 rounded-xl text-xs font-bold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg"
                >
                  <Plus size={14} /> Novo Lançamento
                </button>
              </div>
              <div className="overflow-hidden border border-slate-100 rounded-xl">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400">
                    <tr>
                      <th className="py-4 px-6">Data</th>
                      <th className="py-4 px-6">Categoria</th>
                      <th className="py-4 px-6">Descrição</th>
                      <th className="py-4 px-6 text-right">Valor</th>
                      <th className="py-4 px-6"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {propertyExpenses.map((exp) => (
                      <tr key={exp.id} className="group hover:bg-slate-50 transition-colors">
                        <td className="py-4 px-6 text-xs text-slate-500">{new Date(exp.date).toLocaleDateString('pt-BR')}</td>
                        <td className="py-4 px-6">
