                        <td className="py-4 px-6 text-sm font-black text-slate-900 text-right">{formatCurrency(exp.amount)}</td>
                        <td className="py-4 px-6 text-right">
                          <button onClick={() => onDeleteExpense(exp.id)} className="p-2 text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={16} /></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'timeline' && (
            <div className="space-y-6 animate-in slide-in-from-bottom-2 max-w-2xl mx-auto">
              <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest text-center mb-10">Histórico de Atividades</h4>
              <div className="relative border-l-2 border-slate-100 ml-4 pl-8 space-y-10">
                {propertyLogs.map((log) => (
                  <div key={log.id} className="relative">
                    <div className="absolute -left-11 top-1 w-6 h-6 rounded-full bg-white border-2 border-blue-600 flex items-center justify-center">
                      <Clock size={12} className="text-blue-600" />
                    </div>
                    <div>
                       <div className="flex items-center gap-2 mb-1">
                          <span className="text-xs font-black text-slate-900">{log.action}</span>
                          <span className="text-[10px] text-slate-400 font-medium">at {new Date(log.timestamp).toLocaleString('pt-BR')}</span>
                       </div>
                       <div className="flex items-center gap-2">
                          <div className="flex items-center text-[10px] text-slate-500 font-bold bg-slate-100 px-2 py-0.5 rounded-full">
                             <User size={10} className="mr-1" /> {log.userName}
                          </div>
                          {log.fromStatus && (
                            <div className="flex items-center text-[9px] font-black uppercase text-slate-400">
                               {log.fromStatus} <ArrowRight size={10} className="mx-1" /> {log.toStatus}
                            </div>
                          )}
                       </div>
                    </div>
                  </div>
                ))}
                {propertyLogs.length === 0 && (
                  <div className="text-center py-20 text-slate-300 italic text-sm">Nenhum log registrado ainda.</div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      {isExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-8">
            <h3 className="text-xl font-bold mb-6">Lançar Despesa</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Data</label>
                <input type="date" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" defaultValue={new Date().toISOString().split('T')[0]} id="exp_date" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Categoria</label>
                <select className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" id="exp_cat">
                  {Object.values(ExpenseCategory).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Descrição</label>
                <input type="text" placeholder="Ex: Pintura sala ou IPTU 2024" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" id="exp_desc" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Valor</label>
                <input type="number" placeholder="0,00" className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500" id="exp_amount" />
              </div>
            </div>
            <div className="flex gap-4 mt-8">
              <button onClick={() => setIsExpenseModalOpen(false)} className="flex-1 py-3 text-sm font-bold text-slate-400">Cancelar</button>
              <button onClick={() => {
                const date = (document.getElementById('exp_date') as HTMLInputElement).value;
                const cat = (document.getElementById('exp_cat') as HTMLSelectElement).value as ExpenseCategory;
                const desc = (document.getElementById('exp_desc') as HTMLInputElement).value;
                const amount = parseFloat((document.getElementById('exp_amount') as HTMLInputElement).value);
                if (!desc || isNaN(amount)) return alert('Preencha os campos corretamente');
                onAddExpense({
                  id: Math.random().toString(36).substr(2, 9),
                  propertyId: id!,
                  category: cat,
                  description: desc,
                  amount: amount,
                  date: date,
                  userId: 'u1',
                  userName: 'Carlos Silva',
                  attachments: []
                });
                setIsExpenseModalOpen(false);
              }} className="flex-1 py-3 bg-blue-600 text-white rounded-xl text-sm font-bold shadow-lg">Confirmar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

