import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, X, AlertCircle, Info, Building, MapPin, Calendar, DollarSign, ShieldCheck, HardHat, Landmark } from 'lucide-react';
import { Property, PropertyStatus, PropertyType } from '../types';

interface PropertyFormProps {
  properties?: Property[];
  onSave: (p: Property) => void;
}

const PropertyForm = ({ properties, onSave }: PropertyFormProps) => {
  const navigate = useNavigate();
  const { id } = useParams();

  const [formData, setFormData] = useState<Partial<Property>>({
    status: PropertyStatus.ARREMATADO,
    type: PropertyType.APARTAMENTO,
    acquisitionDate: new Date().toISOString().split('T')[0]
  });

  const [errors, setErrors] = useState<string[]>([]);

  useEffect(() => {
    if (id && properties) {
      const existing = properties.find(p => p.id === id);
      if (existing) setFormData(existing);
    }
  }, [id, properties]);

  const handleChange = (path: string, value: any) => {
    setFormData(prev => ({ ...prev, [path]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: string[] = [];

    if (!formData.neighborhood || !formData.city) {
      newErrors.push('Identificação básica é obrigatória (Bairro e Cidade).');
    }

    if (formData.status === PropertyStatus.VENDIDO && (!formData.salePrice || formData.salePrice <= 0)) {
      newErrors.push('Informe o preço de venda para marcar como Vendido.');
    }

    if (newErrors.length > 0) {
      setErrors(newErrors);
      window.scrollTo(0, 0);
      return;
    }

    const finalData = {
      ...formData,
      id: formData.id || Math.random().toString(36).substr(2, 9),
    } as Property;

    onSave(finalData);
    navigate('/imoveis');
  };

  const InputField = ({ label, path, type = 'number', prefix, placeholder }: any) => {
    const value = (formData as any)[path];

    return (
      <div className="flex-1 min-w-[200px]">
        <label className="block text-[13px] font-semibold text-slate-500 mb-2">{label}</label>
        <div className="relative group">
          {prefix && (
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold text-sm z-10">
              {prefix}
            </span>
          )}
          <input 
            type={type} 
            placeholder={placeholder}
            className={`w-full bg-slate-800 text-slate-100 ${prefix ? 'pl-11' : 'px-4'} py-3 rounded-xl border-none outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-inner placeholder:text-slate-600`}
            value={value || ''}
            onChange={(e) => handleChange(path, type === 'number' ? parseFloat(e.target.value) : e.target.value)}
          />
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-5xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-start justify-between mb-10">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight mb-2">
            {id ? 'Editar Ativo' : 'Cadastro de Novo Ativo'}
          </h2>
          <p className="text-slate-500 font-medium">Preencha os detalhes técnicos e financeiros do imóvel.</p>
        </div>
        <button 
          onClick={() => navigate(-1)}
          className="p-3 bg-white hover:bg-slate-100 text-slate-400 hover:text-slate-600 rounded-full transition-all border border-slate-200"
        >
          <X size={24} />
        </button>
      </div>

      {errors.length > 0 && (
        <div className="mb-8 bg-rose-50 border-l-4 border-rose-500 p-5 rounded-r-2xl flex items-start space-x-4 shadow-sm">
          <AlertCircle className="text-rose-500 shrink-0 mt-0.5" size={24} />
          <div>
            <h4 className="text-rose-900 font-black text-sm uppercase tracking-wider">Atenção Necessária</h4>
            <ul className="list-disc list-inside text-rose-700 text-sm mt-2 space-y-1">
              {errors.map((err, i) => <li key={i} className="font-medium">{err}</li>)}
            </ul>
          </div>
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-10">
        {/* IDENTIFICAÇÃO E STATUS */}
        <section className="bg-white p-8 rounded-[32px] border border-slate-200 shadow-sm space-y-8">
