import { Property, PropertyCalculations, Expense, ExpenseCategory } from './types';

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(value);
};

// Formata um número puro para o padrão visual brasileiro (sem o símbolo R$)
export const formatBRLMask = (value: number | string): string => {
  if (value === undefined || value === null || value === '') return '';
  const numericValue = typeof value === 'string' ? value.replace(/\D/g, '') : Math.round(value * 100).toString();

  if (numericValue === '0' || numericValue === '') return '0,00';

  const integerPart = numericValue.slice(0, -2) || '0';
  const decimalPart = numericValue.slice(-2).padStart(2, '0');

  const formattedInteger = parseInt(integerPart).toLocaleString('pt-BR');
  return `${formattedInteger},${decimalPart}`;
};

// Converte a string mascarada de volta para um número float
export const parseBRLToFloat = (value: string): number => {
  if (!value) return 0;
  const cleanValue = value.replace(/\D/g, '');
  return parseFloat(cleanValue) / 100;
};

export const calculatePropertyMetrics = (p: Property, expenses: Expense[]): PropertyCalculations => {
  const propertyExpenses = expenses.filter(e => e.propertyId === p.id);

  const categoryBreakdown: Record<ExpenseCategory, number> = {
    [ExpenseCategory.REFORMA]: 0,
    [ExpenseCategory.MANUTENCAO]: 0,
    [ExpenseCategory.IMPOSTOS]: 0,
    [ExpenseCategory.LEGAL]: 0,
    [ExpenseCategory.COMERCIAL]: 0,
    [ExpenseCategory.OUTROS]: 0,
  };

  propertyExpenses.forEach(e => {
    categoryBreakdown[e.category] += e.amount;
  });

  const initialInvestment = (p.acquisitionPrice || 0) + (p.auctioneerCommission || 0);
  const totalInvested = initialInvestment + propertyExpenses.reduce((acc, e) => acc + e.amount, 0);

  const costPerM2 = p.sizeM2 > 0 ? totalInvested / p.sizeM2 : 0;
  const realizedProfit = p.salePrice ? (p.salePrice - totalInvested) : 0;
  const roi = totalInvested > 0 ? (realizedProfit / totalInvested) * 100 : 0;

  return {
    totalInvested,
    costPerM2,
    realizedProfit,
    roi,
    categoryBreakdown
  };
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, X, AlertCircle, Info, Landmark, ShieldCheck, HardHat } from 'lucide-react';
import { Property, PropertyStatus, PropertyType } from '../types';
import { formatBRLMask, parseBRLToFloat } from '../utils';

interface InputFieldProps {
  label: string;
  path: string;
  type?: 'text' | 'number' | 'date' | 'currency';
  prefix?: string;
  placeholder?: string;
  value: any;
  onChange: (path: string, value: any) => void;
}

const InputField = ({ label, path, type = 'text', prefix, placeholder, value, onChange }: InputFieldProps) => {
  // Estado local para gerenciar a string da máscara sem perder o foco ou causar saltos no cursor
  const displayValue = type === 'currency' ? formatBRLMask(value) : (value === undefined || value === null ? '' : value);

  return (
    <div className="flex-1 min-w-[200px]">
      <label className="block text-[13px] font-semibold text-slate-500 mb-2">{label}</label>
      <div className="relative group">
        {prefix && (
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold text-sm z-10 pointer-events-none">
            {prefix}
          </span>
        )}
        <input 
          type={type === 'currency' ? 'text' : type} 
          placeholder={placeholder}
          className={`w-full bg-slate-800 text-slate-100 ${prefix ? 'pl-11' : 'px-4'} py-3 rounded-xl border-none outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-inner placeholder:text-slate-600 font-medium`}
          value={displayValue}
          onChange={(e) => {
            const rawValue = e.target.value;
            if (type === 'currency') {
              // Apenas números são permitidos na entrada de moeda
              const numeric = rawValue.replace(/\D/g, '');
              onChange(path, parseBRLToFloat(numeric));
            } else if (type === 'number') {
              const num = parseFloat(rawValue);
              onChange(path, isNaN(num) ? 0 : num);
            } else {
              onChange(path, rawValue);
            }
          }}
        />
      </div>
    </div>
  );
};

const PropertyForm = ({ properties, onSave }: { properties?: Property[], onSave: (p: Property) => void }) => {
  const navigate = useNavigate();
  const { id } = useParams();

  const [formData, setFormData] = useState<Partial<Property>>({
    status: PropertyStatus.ARREMATADO,
    type: PropertyType.APARTAMENTO,
    acquisitionDate: new Date().toISOString().split('T')[0],
    acquisitionPrice: 0,
    auctioneerCommission: 0,
    sizeM2: 0,
    bankValuation: 0
  });

  const [errors, setErrors] = useState<string[]>([]);

  useEffect(() => {
    if (id && properties) {
      const existing = properties.find(p => p.id === id);
      if (existing) setFormData(existing);
    }
  }, [id, properties]);

  const handleChange = (path: string, value: any) => {
    setFormData(prev => ({ ...prev, [path]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: string[] = [];

    // Validações de Identificação
    if (!formData.neighborhood || formData.neighborhood.trim().length < 3) {
      newErrors.push('O Bairro/Condomínio deve ter pelo menos 3 caracteres.');
    }
    if (!formData.city || formData.city.trim().length < 2) {
      newErrors.push('A Cidade é obrigatória.');
    }

    // Validações de Valores (Lógica de Negócio)
    if ((formData.acquisitionPrice || 0) <= 0) {
      newErrors.push('O Preço de Aquisição deve ser maior que zero.');
    }
    if ((formData.sizeM2 || 0) <= 0) {
      newErrors.push('O Tamanho Privativo deve ser maior que zero.');
    }

    // Validação de Datas
    const acqDate = new Date(formData.acquisitionDate || '');
    const today = new Date();
    const minDate = new Date('2000-01-01');

    if (acqDate > today) {
      newErrors.push('A Data de Aquisição não pode ser no futuro.');
    }
    if (acqDate < minDate) {
      newErrors.push('A Data de Aquisição é muito antiga para o sistema.');
    }

    // Validação de Status de Venda
    if (formData.status === PropertyStatus.VENDIDO) {
      if ((formData.salePrice || 0) <= (formData.acquisitionPrice || 0)) {
        newErrors.push('Alerta: O Preço de Venda informado é menor ou igual ao de aquisição. Verifique a rentabilidade.');
      }
    }

    if (newErrors.length > 0) {
      setErrors(newErrors);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    const finalData = {
      ...formData,
      id: formData.id || Math.random().toString(36).substr(2, 9),
    } as Property;

    onSave(finalData);
    navigate('/imoveis');
  };

  return (
    <div className="max-w-5xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-start justify-between mb-10">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight mb-2">
            {id ? 'Editar Ativo' : 'Cadastro de Novo Ativo'}
          </h2>
          <p className="text-slate-500 font-medium">Preencha os detalhes técnicos e financeiros do imóvel.</p>
        </div>
        <button 
          type="button"
          onClick={() => navigate(-1)}
          className="p-3 bg-white hover:bg-slate-100 text-slate-400 hover:text-slate-600 rounded-full transition-all border border-slate-200 shadow-sm"
        >
          <X size={24} />
        </button>
      </div>

      {errors.length > 0 && (
        <div className="mb-8 bg-rose-50 border-l-4 border-rose-500 p-6 rounded-r-2xl flex items-start space-x-4 shadow-md animate-in slide-in-from-top-4">
          <AlertCircle className="text-rose-500 shrink-0 mt-0.5" size={24} />
          <div>
            <h4 className="text-rose-900 font-black text-sm uppercase tracking-wider mb-1">Inconsistências Encontradas</h4>
            <ul className="list-disc list-inside text-rose-700 text-sm space-y-1">
              {errors.map((err, i) => <li key={i} className="font-medium">{err}</li>)}
            </ul>
          </div>
        </div>
