  finances: ['view', 'edit', 'delete'],
  teams: ['view', 'edit', 'delete'],
  reports: ['view', 'edit', 'delete']
};

const INITIAL_MASTER: UserAccount = {
  id: 'u-master',
  name: 'Diretoria Master',
  email: 'admin@masterimoveis.com',
  role: UserRole.MASTER,
  active: true,
  permissions: INITIAL_PERMISSIONS
};

const SidebarItem = ({ to, icon: Icon, label, active, visible = true }: { to?: string, icon: any, label: string, active: boolean, visible?: boolean }) => {
  if (!visible) return null;
  const content = (
    <div className={`flex items-center space-x-3 p-3 rounded-lg transition-colors cursor-pointer ${
      active 
        ? 'bg-blue-600 text-white shadow-lg' 
        : 'text-slate-400 hover:bg-slate-800 hover:text-white'
    }`}>
      <Icon size={20} />
      <span className="font-medium flex-1">{label}</span>
    </div>
  );
  return to ? <Link to={to}>{content}</Link> : <div>{content}</div>;
};

const SidebarGroup = ({ label, icon: Icon, children, active, visible = true }: { label: string, icon: any, children?: React.ReactNode, active: boolean, visible?: boolean }) => {
  const [isOpen, setIsOpen] = useState(active);
  if (!visible) return null;
  return (
    <div className="space-y-1">
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className={`flex items-center space-x-3 p-3 rounded-lg transition-colors cursor-pointer ${
          active && !isOpen ? 'bg-blue-600/20 text-blue-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
        }`}
      >
        <Icon size={20} />
        <span className="font-medium flex-1">{label}</span>
        {isOpen ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
      </div>
      {isOpen && (
        <div className="pl-11 space-y-1 animate-in slide-in-from-top-2 duration-200">
          {children}
        </div>
      )}
    </div>
  );
};

const AppContent = () => {
  const [currentUser] = useState<UserAccount>(INITIAL_MASTER);
  const [properties, setProperties] = useState<Property[]>(() => JSON.parse(localStorage.getItem('master_imoveis_data') || '[]'));
  const [expenses, setExpenses] = useState<Expense[]>(() => JSON.parse(localStorage.getItem('master_imoveis_expenses') || '[]'));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => JSON.parse(localStorage.getItem('master_imoveis_inventory') || '[]'));
  const [movements, setMovements] = useState<StockMovement[]>(() => JSON.parse(localStorage.getItem('master_imoveis_movements') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('master_imoveis_suppliers') || '[]'));
  const [warehouses, setWarehouses] = useState<Warehouse[]>(() => JSON.parse(localStorage.getItem('master_imoveis_warehouses') || '[]'));
  const [users, setUsers] = useState<UserAccount[]>(() => {
    const saved = localStorage.getItem('master_imoveis_users');
    if (saved) return JSON.parse(saved);
    return [INITIAL_MASTER];
  });
  const [teams, setTeams] = useState<Team[]>(() => JSON.parse(localStorage.getItem('master_imoveis_teams') || '[]'));
  const [logs, setLogs] = useState<PropertyLog[]>(() => JSON.parse(localStorage.getItem('master_imoveis_logs') || '[]'));

  const location = useLocation();

  const hasPermission = useCallback((module: PermissionModule, action: PermissionAction): boolean => {
    if (currentUser.role === UserRole.MASTER) return true;
    if (!currentUser.permissions || !currentUser.permissions[module]) return false;
    return currentUser.permissions[module].includes(action);
  }, [currentUser]);

  const addLog = useCallback((log: Omit<PropertyLog, 'id' | 'timestamp' | 'userId' | 'userName'>) => {
    const newLog: PropertyLog = {
      ...log,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      userId: currentUser.id,
      userName: currentUser.name
    };
    setLogs(prev => [newLog, ...prev]);
  }, [currentUser]);

  const updatePropertyStatus = useCallback((propertyId: string, newStatus: PropertyStatus) => {
    const property = properties.find(p => p.id === propertyId);
    if (!property) return;

    const oldStatus = property.status;
    setProperties(prev => prev.map(p => p.id === propertyId ? { ...p, status: newStatus } : p));

    addLog({
      propertyId,
      action: `Status alterado de ${oldStatus} para ${newStatus}`,
      fromStatus: oldStatus,
      toStatus: newStatus
    });
  }, [properties, addLog]);

  const handleAddMovement = useCallback((mov: StockMovement) => {
    setMovements(prev => [mov, ...prev]);

    setInventory(prev => prev.map(item => {
      if (item.id === mov.itemId) {
        const change = mov.type === MovementType.ENTRADA_COMPRA ? mov.quantity : -mov.quantity;
        return { ...item, currentStock: item.currentStock + change };
      }
      return item;
    }));

    if (mov.type === MovementType.SAIDA_OBRA && mov.propertyId) {
      const item = inventory.find(i => i.id === mov.itemId);
      const newExpense: Expense = {
        id: `exp-auto-${mov.id}`,
        propertyId: mov.propertyId,
        category: ExpenseCategory.REFORMA,
        description: `Consumo Estoque: ${item?.name || 'Insumo'} (${mov.quantity} ${item?.unit || ''})`,
        amount: mov.totalPrice,
        date: mov.date,
        userId: currentUser.id,
        userName: currentUser.name,
        attachments: []
      };
      setExpenses(prev => [newExpense, ...prev]);
      addLog({
        propertyId: mov.propertyId,
        action: `Gasto de estoque registrado: ${newExpense.description}`
      });
    }
  }, [inventory, currentUser, addLog]);

  useEffect(() => {
    localStorage.setItem('master_imoveis_data', JSON.stringify(properties));
    localStorage.setItem('master_imoveis_expenses', JSON.stringify(expenses));
    localStorage.setItem('master_imoveis_inventory', JSON.stringify(inventory));
    localStorage.setItem('master_imoveis_movements', JSON.stringify(movements));
    localStorage.setItem('master_imoveis_suppliers', JSON.stringify(suppliers));
    localStorage.setItem('master_imoveis_warehouses', JSON.stringify(warehouses));
    localStorage.setItem('master_imoveis_users', JSON.stringify(users));
    localStorage.setItem('master_imoveis_teams', JSON.stringify(teams));
    localStorage.setItem('master_imoveis_logs', JSON.stringify(logs));
  }, [properties, expenses, inventory, movements, suppliers, warehouses, users, teams, logs]);

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 text-white flex flex-col p-6 sticky top-0 h-screen overflow-y-auto z-20 shadow-2xl">
        <div className="flex items-center space-x-3 mb-10 px-2 group">
          <div className="bg-blue-600 p-2 rounded-xl group-hover:rotate-12 transition-transform">
            <Building2 size={24} />
          </div>
          <div>
            <h1 className="text-lg font-bold leading-none">Master Imóveis</h1>
            <span className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Portal ERP</span>
          </div>
        </div>

        <nav className="flex-1 space-y-2">
          <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} />

          <div className="pt-4 pb-2 px-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider">Gestão Operacional</div>
          <SidebarItem to="/imoveis" icon={Home} label="Imóveis" active={location.pathname.startsWith('/imoveis')} visible={hasPermission('properties', 'view')} />

          <SidebarGroup label="Estoque" icon={Box} active={location.pathname.startsWith('/estoque')} visible={hasPermission('inventory', 'view')}>
            <Link to="/estoque/insumos" className={`block py-2 text-sm font-medium ${location.pathname === '/estoque/insumos' ? 'text-blue-500' : 'text-slate-500 hover:text-white'}`}>• Insumos</Link>
            <Link to="/estoque/movimentos" className={`block py-2 text-sm font-medium ${location.pathname === '/estoque/movimentos' ? 'text-blue-500' : 'text-slate-500 hover:text-white'}`}>• Movimentos</Link>
            <Link to="/estoque/fornecedores" className={`block py-2 text-sm font-medium ${location.pathname === '/estoque/fornecedores' ? 'text-blue-500' : 'text-slate-500 hover:text-white'}`}>• Fornecedores</Link>
          </SidebarGroup>

          <div className="pt-4 pb-2 px-2 text-[10px] font-bold text-slate-500 uppercase tracking-wider">Estratégico</div>
          <SidebarItem to="/relatorios" icon={BarChart3} label="Relatórios" active={location.pathname === '/relatorios'} visible={hasPermission('reports', 'view')} />
          <SidebarItem to="/equipe" icon={Users} label="Equipe" active={location.pathname === '/equipe'} visible={hasPermission('teams', 'view')} />
        </nav>

        <div className="mt-auto pt-6 border-t border-slate-800 space-y-4">
          <div className="flex items-center space-x-3 px-2 py-3 bg-slate-800/50 rounded-xl text-xs font-bold uppercase truncate">
            {currentUser.name}
          </div>
          <SidebarItem to="/configuracoes" icon={Settings} label="Ajustes" active={location.pathname === '/configuracoes'} />
          <button className="flex items-center space-x-3 p-3 w-full rounded-lg text-rose-400 hover:bg-rose-500/10 transition-colors">
            <LogOut size={20} />
            <span className="font-medium">Sair</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        <Routes>
          <Route path="/" element={<Dashboard properties={properties} expenses={expenses} />} />
          <Route path="/imoveis" element={<PropertyList properties={properties} expenses={expenses} onUpdateStatus={updatePropertyStatus} />} />
          <Route path="/imovel/:id" element={<PropertyDetails properties={properties} expenses={expenses} logs={logs} onAddExpense={(e) => { setExpenses(prev => [e, ...prev]); addLog({ propertyId: e.propertyId, action: `Lançamento de despesa: ${e.description}` }); }} onDeleteExpense={(id) => setExpenses(prev => prev.filter(e => e.id !== id))} />} />
          <Route path="/novo" element={<PropertyForm onSave={(p) => { setProperties(prev => [...prev, p]); addLog({ propertyId: p.id, action: "Imóvel cadastrado" }); }} />} />
          <Route path="/estoque/insumos" element={<InsumosPage items={inventory} setItems={setInventory} />} />
          <Route path="/estoque/movimentos" element={<MovimentosPage movements={movements} items={inventory} suppliers={suppliers} properties={properties} onAddMovement={handleAddMovement} />} />
          <Route path="/estoque/fornecedores" element={<FornecedoresPage suppliers={suppliers} setSuppliers={setSuppliers} />} />
          <Route path="/estoque/almoxarifados" element={<AlmoxarifadosPage warehouses={warehouses} setWarehouses={setWarehouses} />} />
          <Route path="/relatorios" element={<ReportsPage properties={properties} expenses={expenses} inventory={inventory} />} />
          <Route path="/equipe" element={<TeamsPage currentUser={currentUser} users={users} setUsers={setUsers} teams={teams} setTeams={setTeams} />} />
          <Route path="/configuracoes" element={<SettingsPage />} />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </main>
    </div>
  );
};

const App = () => (
  <HashRouter>
    <AppContent />
  </HashRouter>
);

export default App;

import React, { useState } from 'react';
import { 
  Users, Plus, Shield, Trash2, Edit, UserPlus, Mail, 
  Briefcase, UserCircle, Key, Check, X, ShieldAlert 
} from 'lucide-react';
import { UserAccount, UserRole, Team, UserPermissions, PermissionAction, PermissionModule } from '../types';

interface TeamsPageProps {
  currentUser: UserAccount;
  users: UserAccount[];
  setUsers: React.Dispatch<React.SetStateAction<UserAccount[]>>;
  teams: Team[];
  setTeams: React.Dispatch<React.SetStateAction<Team[]>>;
}

const DEFAULT_COLLAB_PERMISSIONS: UserPermissions = {
  properties: ['view'],
  inventory: ['view'],
  finances: [],
  teams: [],
  reports: ['view']
};

const TeamsPage = ({ currentUser, users, setUsers, teams, setTeams }: TeamsPageProps) => {
  const [activeTab, setActiveTab] = useState<'users' | 'teams'>('users');
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isPermModalOpen, setIsPermModalOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState<UserAccount | null>(null);

  const isMaster = currentUser.role === UserRole.MASTER;

  const addUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isMaster) return;
    const form = e.target as HTMLFormElement;
    const role = (form.elements.namedItem('role') as HTMLSelectElement).value as UserRole;

    const newUser: UserAccount = {
      id: Math.random().toString(36).substr(2, 9),
      name: (form.elements.namedItem('name') as HTMLInputElement).value,
      email: (form.elements.namedItem('email') as HTMLInputElement).value,
      role: role,
      teamId: (form.elements.namedItem('teamId') as HTMLSelectElement).value || undefined,
      active: true,
      permissions: role === UserRole.MASTER ? {
        properties: ['view', 'edit', 'delete'],
        inventory: ['view', 'edit', 'delete'],
        finances: ['view', 'edit', 'delete'],
        teams: ['view', 'edit', 'delete'],
        reports: ['view', 'edit', 'delete']
      } : { ...DEFAULT_COLLAB_PERMISSIONS }
    };
    setUsers([...users, newUser]);
    setIsUserModalOpen(false);
  };

  const togglePermission = (module: PermissionModule, action: PermissionAction) => {
    if (!selectedUser || !selectedUser.permissions) return;
    const currentPerms = selectedUser.permissions[module] || [];
    const newPerms = currentPerms.includes(action)
      ? currentPerms.filter(a => a !== action)
      : [...currentPerms, action];

    const updatedUser = {
      ...selectedUser,
      permissions: {
        ...selectedUser.permissions,
        [module]: newPerms
      }
    };
    setSelectedUser(updatedUser);
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Governança e Equipe</h2>
          <p className="text-slate-500 font-medium">Controle de acessos e estrutura organizacional.</p>
        </div>
        <div className="flex gap-4">
          {isMaster && (
            <button 
              onClick={() => setIsUserModalOpen(true)}
              className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-bold text-sm hover:bg-blue-700 transition-all shadow-lg flex items-center gap-2"
            >
              <UserPlus size={18} /> Novo Acesso
            </button>
          )}
        </div>
      </div>

      <div className="flex border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('users')}
          className={`px-8 py-4 text-sm font-bold uppercase tracking-wider transition-all ${activeTab === 'users' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-400'}`}
        >
          Usuários
        </button>
        <button 
          onClick={() => setActiveTab('teams')}
          className={`px-8 py-4 text-sm font-bold uppercase tracking-wider transition-all ${activeTab === 'teams' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-400'}`}
        >
          Departamentos
        </button>
      </div>

      {activeTab === 'users' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {users.map(u => (
            <div key={u.id} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm group">
              <div className="flex items-start justify-between mb-4">
                <div className="w-12 h-12 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-600">
                  <UserCircle size={28} />
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                  {isMaster && u.role !== UserRole.MASTER && (
                    <button 
                      onClick={() => { setSelectedUser(u); setIsPermModalOpen(true); }}
                      className="p-2 text-slate-400 hover:text-blue-600"
                      title="Gerenciar Permissões"
                    >
                      <Key size={18} />
                    </button>
                  )}
                  {isMaster && u.id !== currentUser.id && (
                    <button className="p-2 text-slate-400 hover:text-rose-600"><Trash2 size={18} /></button>
                  )}
                </div>
              </div>
              <h3 className="font-bold text-slate-900 mb-1">{u.name}</h3>
              <p className="text-xs text-slate-500 mb-4">{u.email}</p>

              <div className="flex items-center justify-between mt-4 pt-4 border-t border-slate-100">
                <span className={`px-2 py-1 rounded text-[10px] font-black uppercase tracking-widest ${u.role === UserRole.MASTER ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
                  {u.role}
                </span>
                <div className="flex -space-x-1">
                  {u.permissions && Object.keys(u.permissions).map(mod => (
                    u.permissions[mod as PermissionModule]?.length > 0 && (
                      <div key={mod} className="w-2 h-2 rounded-full bg-emerald-500 border border-white" title={mod} />
                    )
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {isPermModalOpen && selectedUser && selectedUser.permissions && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
              <div className="flex items-center gap-3">
                <Shield size={24} className="text-blue-400" />
                <div>
                  <h3 className="font-bold">Acessos de {selectedUser.name}</h3>
                  <p className="text-[10px] uppercase font-bold text-slate-400">Controle de Segurança ERP</p>
                </div>
              </div>
              <button onClick={() => setIsPermModalOpen(false)}><X size={24} /></button>
            </div>

            <div className="p-8">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-xs font-bold text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="py-4">Módulo</th>
                    <th className="py-4 text-center">Visualizar</th>
                    <th className="py-4 text-center">Editar/Criar</th>
                    <th className="py-4 text-center">Excluir</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {([
                    { id: 'properties', label: 'Imóveis' },
                    { id: 'inventory', label: 'Estoque' },
                    { id: 'finances', label: 'Financeiro' },
                    { id: 'teams', label: 'Equipe' },
                    { id: 'reports', label: 'BI / Relatórios' }
                  ] as const).map(mod => (
                    <tr key={mod.id}>
                      <td className="py-4 font-bold text-slate-700 text-sm">{mod.label}</td>
                      {(['view', 'edit', 'delete'] as const).map(act => (
                        <td key={act} className="py-4 text-center">
                          <button 
                            onClick={() => togglePermission(mod.id, act)}
                            className={`w-6 h-6 rounded flex items-center justify-center transition-all ${
                              selectedUser.permissions[mod.id]?.includes(act) 
                                ? 'bg-blue-600 text-white' 
                                : 'bg-slate-100 text-slate-300 hover:bg-slate-200'
                            }`}
                          >
                            <Check size={14} strokeWidth={4} />
                          </button>
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>

              <div className="mt-8 p-4 bg-amber-50 rounded-xl flex items-start gap-3 border border-amber-100">
                <ShieldAlert className="text-amber-600 shrink-0" size={20} />
                <p className="text-xs text-amber-700 leading-relaxed font-medium">
                  Alterações nas permissões entram em vigor imediatamente na próxima navegação do colaborador. 
                </p>
              </div>

              <div className="mt-8 flex justify-end">
                <button 
                  onClick={() => setIsPermModalOpen(false)}
                  className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold shadow-lg"
                >
                  Concluir Ajustes
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {isUserModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <form onSubmit={addUser} className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-8">
            <h3 className="text-xl font-bold mb-6">Cadastrar Novo Usuário</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Nome Completo</label>
                <input required name="name" type="text" className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">E-mail</label>
                <input required name="email" type="email" className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Nível de Acesso</label>
                <select name="role" className="w-full px-3 py-2 border border-slate-200 rounded-lg">
                  <option value={UserRole.COLABORADOR}>Colaborador</option>
                  <option value={UserRole.MASTER}>Master</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Departamento</label>
                <select name="teamId" className="w-full px-3 py-2 border border-slate-200 rounded-lg">
                  <option value="">Nenhum</option>
                  {teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
