      </div>

      {activeTab === 'users' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {users.map(u => {
            const team = teams.find(t => t.id === u.teamId);
            return (
              <div key={u.id} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm group">
