import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, X, AlertCircle, Info, Landmark, ShieldCheck, HardHat, Image as ImageIcon, Plus, Trash2 } from 'lucide-react';
import { Property, PropertyStatus, PropertyType } from '../types';
import { formatBRLMask, parseBRLToFloat } from '../utils';

interface InputFieldProps {
  label: string;
  path: string;
  type?: 'text' | 'number' | 'date' | 'currency';
  prefix?: string;
  placeholder?: string;
  value: any;
  onChange: (path: string, value: any) => void;
}

const InputField = ({ label, path, type = 'text', prefix, placeholder, value, onChange }: InputFieldProps) => {
  const displayValue = type === 'currency' ? formatBRLMask(value) : (value === undefined || value === null ? '' : value);

  return (
    <div className="flex-1 min-w-[200px]">
      <label className="block text-[13px] font-bold text-slate-500 mb-2 uppercase tracking-wider">{label}</label>
      <div className="relative group">
        {prefix && (
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold text-sm z-10 pointer-events-none">
            {prefix}
          </span>
        )}
        <input 
          type={type === 'currency' ? 'text' : type} 
          placeholder={placeholder}
          className={`w-full bg-slate-800 text-slate-100 ${prefix ? 'pl-11' : 'px-4'} py-3.5 rounded-2xl border-none outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-xl placeholder:text-slate-500 font-medium`}
          value={displayValue}
          onChange={(e) => {
            const rawValue = e.target.value;
            if (type === 'currency') {
              const numeric = rawValue.replace(/\D/g, '');
              onChange(path, parseBRLToFloat(numeric));
            } else if (type === 'number') {
              const num = parseFloat(rawValue);
              onChange(path, isNaN(num) ? 0 : num);
            } else {
              onChange(path, rawValue);
            }
          }}
        />
      </div>
    </div>
  );
};

const PropertyForm = ({ properties, onSave }: { properties?: Property[], onSave: (p: Property) => void }) => {
  const navigate = useNavigate();
  const { id } = useParams();

  const [formData, setFormData] = useState<Partial<Property>>({
    status: PropertyStatus.ARREMATADO,
    type: PropertyType.APARTAMENTO,
    acquisitionDate: new Date().toISOString().split('T')[0],
    acquisitionPrice: 0,
    auctioneerCommission: 0,
    sizeM2: 0,
    bankValuation: 0,
    legalEscritura: 0,
    legalItbi: 0,
    legalTaxasRegistro: 0,
    budgetReforma: 0,
    salePrice: 0,
    brokerage: 0,
    salesTax: 0,
    images: []
  });

  const [imageUrlInput, setImageUrlInput] = useState('');
  const [errors, setErrors] = useState<string[]>([]);

  useEffect(() => {
    if (id && properties) {
      const existing = properties.find(p => p.id === id);
      if (existing) setFormData(existing);
    }
  }, [id, properties]);

  const handleChange = (path: string, value: any) => {
    setFormData(prev => ({ ...prev, [path]: value }));
  };

  const addImage = () => {
    if (!imageUrlInput) return;
    setFormData(prev => ({
      ...prev,
      images: [...(prev.images || []), imageUrlInput]
    }));
    setImageUrlInput('');
  };

  const removeImage = (index: number) => {
    setFormData(prev => ({
      ...prev,
      images: (prev.images || []).filter((_, i) => i !== index)
