                const date = (document.getElementById('exp_date') as HTMLInputElement).value;
                const cat = (document.getElementById('exp_cat') as HTMLSelectElement).value as ExpenseCategory;
                const desc = (document.getElementById('exp_desc') as HTMLInputElement).value;
                const amount = parseFloat((document.getElementById('exp_amount') as HTMLInputElement).value);
