                onAddExpense({
                  id: Math.random().toString(36).substr(2, 9),
                  propertyId: id!,
                  category: cat,
                  description: desc,
                  amount: amount,
                  date: date,
                  userId: 'u1',
                  userName: 'Diretoria Master',
                  attachments: []
                });
                setIsExpenseModalOpen(false);
              }} className="flex-1 py-4 bg-blue-600 text-white rounded-[20px] text-xs font-black uppercase tracking-widest shadow-2xl shadow-blue-500/30 hover:bg-blue-700 transition-all">Confirmar Lançamento</button>
            </div>
