              <th className="px-8 py-6">Operação</th>
              <th className="px-8 py-6">Insumo</th>
              <th className="px-8 py-6">Qtd</th>
              <th className="px-8 py-6">Unitário</th>
              <th className="px-8 py-6">Destinação</th>
              <th className="px-8 py-6 text-right">Valor Total</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {movements.map((mov) => {
              const item = items.find(i => i.id === mov.itemId);
              const property = properties.find(p => p.id === mov.propertyId);
              return (
                <tr key={mov.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-8 py-6 text-xs font-bold text-slate-500">{new Date(mov.date).toLocaleDateString('pt-BR')}</td>
                  <td className="px-8 py-6">
                    <span className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-wider ${
                      mov.type === MovementType.ENTRADA_COMPRA ? 'bg-emerald-500 text-white' : 
                      mov.type === MovementType.SAIDA_OBRA ? 'bg-amber-500 text-white' : 'bg-slate-200 text-slate-600'
                    }`}>
                      {mov.type}
                    </span>
                  </td>
                  <td className="px-8 py-6 font-black text-slate-800 tracking-tight">{item?.name || '---'}</td>
                  <td className="px-8 py-6 text-sm font-bold text-slate-600">{mov.quantity} <span className="text-[10px] font-normal">{item?.unit}</span></td>
