                    )}
                  </td>
                  <td className="px-8 py-6 text-right font-black text-slate-900 text-base">{formatCurrency(mov.totalPrice)}</td>
                </tr>
              );
            })}
            {movements.length === 0 && (
              <tr>
                <td colSpan={7} className="py-24 text-center text-slate-300 italic font-medium tracking-widest uppercase text-xs">Aguardando primeira movimentação...</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-xl p-12 animate-in zoom-in-95 duration-200">
