            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2">Tipo de Operação</label>
                  <select name="type" required className="w-full bg-slate-800 text-slate-100 px-5 py-4 rounded-2xl border-none outline-none focus:ring-2 focus:ring-blue-500 shadow-xl font-medium appearance-none">
                    {Object.values(MovementType).map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2">Data da Ação</label>
                  <input name="date" required type="date" className="w-full bg-slate-800 text-slate-100 px-5 py-4 rounded-2xl border-none outline-none focus:ring-2 focus:ring-blue-500 shadow-xl font-medium" defaultValue={new Date().toISOString().split('T')[0]} />
