                  <label className="block text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2">Fornecedor Origem</label>
                  <select name="supplierId" className="w-full bg-slate-800 text-slate-100 px-5 py-4 rounded-2xl border-none outline-none focus:ring-2 focus:ring-blue-500 shadow-xl font-medium appearance-none">
