          <KanbanColumn status={PropertyStatus.A_VENDA} items={filteredProperties.filter(p => p.status === PropertyStatus.A_VENDA)} />
          <KanbanColumn status={PropertyStatus.VENDIDO} items={filteredProperties.filter(p => p.status === PropertyStatus.VENDIDO)} />
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {filteredProperties.map(p => {
             const metrics = calculatePropertyMetrics(p, expenses);
             return (
              <div key={p.id} onClick={() => navigate(`/imovel/${p.id}`)} className="bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden hover:shadow-2xl hover:-translate-y-2 transition-all cursor-pointer group">
