                       <h3 className="font-black text-slate-900 truncate flex-1 tracking-tight text-lg">{p.neighborhood}</h3>
                       <div className="text-emerald-600 font-black text-sm">{metrics.roi.toFixed(0)}% ROI</div>
                    </div>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-6">{p.city}</p>
                    <div className="flex justify-between items-end border-t border-slate-50 pt-5">
                       <div>
