                       <div className="bg-slate-100 p-3 rounded-2xl group-hover:bg-blue-600 group-hover:text-white transition-colors">
                        <ArrowRight size={20} />
                       </div>
                    </div>
                 </div>
              </div>
             );
          })}
        </div>
      )}
    </div>
  );
};

