            className="w-full pl-14 pr-6 py-4.5 bg-slate-800 text-slate-100 border-none rounded-[20px] focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-slate-500 font-medium shadow-inner"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
