import React, { useState, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Search, MapPin, Building, ChevronRight, LayoutGrid, Kanban as KanbanIcon, ArrowRight, Image as ImageIcon, Plus } from 'lucide-react';
import { Property, PropertyStatus, Expense } from '../types';
import { formatCurrency, calculatePropertyMetrics } from '../utils';

interface PropertyListProps {
  properties: Property[];
  expenses: Expense[];
  onUpdateStatus: (id: string, status: PropertyStatus) => void;
}

const PropertyList = ({ properties, expenses, onUpdateStatus }: PropertyListProps) => {
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<'grid' | 'kanban'>('kanban');
  const [search, setSearch] = useState('');

  const filteredProperties = useMemo(() => {
    return properties.filter(p => 
      p.neighborhood.toLowerCase().includes(search.toLowerCase()) || 
      p.city.toLowerCase().includes(search.toLowerCase())
    );
  }, [properties, search]);

  const onDragStart = (e: React.DragEvent, propertyId: string) => {
    e.dataTransfer.setData('propertyId', propertyId);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const onDrop = (e: React.DragEvent, status: PropertyStatus) => {
    const propertyId = e.dataTransfer.getData('propertyId');
    onUpdateStatus(propertyId, status);
  };

  const KanbanColumn = ({ status, items }: { status: PropertyStatus, items: Property[] }) => (
    <div 
      onDragOver={onDragOver}
      onDrop={(e) => onDrop(e, status)}
      className="flex flex-col min-w-[320px] max-w-[360px] bg-slate-100/50 rounded-[40px] p-5 min-h-[700px] border border-dashed border-slate-200"
    >
      <div className="flex items-center justify-between mb-6 px-3">
        <h3 className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">{status}</h3>
        <span className="bg-white px-3 py-1 rounded-full text-[10px] font-black text-blue-600 shadow-sm border border-slate-100">{items.length}</span>
      </div>

      <div className="space-y-5">
        {items.map(p => {
          const metrics = calculatePropertyMetrics(p, expenses);
          return (
            <div 
              key={p.id}
              draggable
              onDragStart={(e) => onDragStart(e, p.id)}
              onClick={() => navigate(`/imovel/${p.id}`)}
              className="bg-white rounded-3xl border border-slate-200 shadow-sm hover:shadow-xl hover:shadow-blue-500/10 hover:-translate-y-1.5 hover:scale-[1.02] transition-all duration-300 cursor-grab active:cursor-grabbing overflow-hidden group"
            >
              {p.images && p.images.length > 0 ? (
                <img src={p.images[0]} className="w-full h-24 object-cover transition-transform duration-500 group-hover:scale-110" alt={p.neighborhood} />
              ) : (
                <div className="w-full h-24 bg-slate-100 flex items-center justify-center text-slate-300">
                  <ImageIcon size={24} />
                </div>
              )}
              <div className="p-5">
                <div className="flex justify-between items-start mb-2">
                  <h4 className="font-bold text-slate-900 text-sm truncate leading-tight flex-1 tracking-tight">{p.neighborhood}</h4>
                  <div className="text-[10px] text-emerald-600 font-black bg-emerald-50 px-2 py-0.5 rounded ml-2">
                    {metrics.roi.toFixed(0)}%
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest flex items-center mb-4">
                  <MapPin size={10} className="mr-1" /> {p.city}
                </p>
                <div className="flex justify-between items-center pt-4 border-t border-slate-50">
                  <span className="text-xs font-black text-slate-900">{formatCurrency(metrics.totalInvested)}</span>
                  <div className="bg-slate-50 p-1.5 rounded-lg text-slate-300 group-hover:text-blue-600 group-hover:bg-blue-50 transition-colors">
                    <ChevronRight size={14} />
                  </div>
                </div>
              </div>
            </div>
          );
        })}
        {items.length === 0 && (
          <div className="flex-1 flex flex-col items-center justify-center py-20 text-slate-300 text-[10px] uppercase font-black text-center italic tracking-widest">
            <Building size={24} className="mb-2 opacity-20" />
            Vazio
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Ativos em Carteira</h2>
          <p className="text-slate-500 font-medium">Fluxo de arremates e status das obras.</p>
        </div>
        <div className="flex items-center gap-4">
           <div className="bg-white border border-slate-200 rounded-2xl p-1.5 flex shadow-sm">
              <button 
                onClick={() => setViewMode('kanban')}
                className={`p-2.5 rounded-xl transition-all ${viewMode === 'kanban' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <KanbanIcon size={20} />
              </button>
              <button 
                onClick={() => setViewMode('grid')}
                className={`p-2.5 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <LayoutGrid size={20} />
              </button>
           </div>
           <Link to="/novo" className="bg-blue-600 text-white px-8 py-3.5 rounded-[24px] font-black hover:bg-blue-700 transition-all flex items-center space-x-3 shadow-2xl shadow-blue-500/20">
            <Plus size={22} strokeWidth={3} /> <span>Novo Ativo</span>
           </Link>
        </div>
      </div>

      <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm">
        <div className="relative w-full">
          <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Pesquisar por condomínio, bairro ou cidade..." 
            className="w-full pl-14 pr-6 py-4.5 bg-slate-50 text-slate-900 border border-slate-200 rounded-[20px] focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 outline-none font-medium placeholder:text-slate-400 transition-all"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </div>

      {viewMode === 'kanban' ? (
        <div className="flex gap-8 overflow-x-auto pb-10 snap-x">
          <KanbanColumn status={PropertyStatus.ARREMATADO} items={filteredProperties.filter(p => p.status === PropertyStatus.ARREMATADO)} />
          <KanbanColumn status={PropertyStatus.EM_REFORMA} items={filteredProperties.filter(p => p.status === PropertyStatus.EM_REFORMA)} />
          <KanbanColumn status={PropertyStatus.A_VENDA} items={filteredProperties.filter(p => p.status === PropertyStatus.A_VENDA)} />
          <KanbanColumn status={PropertyStatus.VENDIDO} items={filteredProperties.filter(p => p.status === PropertyStatus.VENDIDO)} />
        </div>
      ) : (
