import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, X, AlertCircle, Info, Landmark, ShieldCheck, HardHat, Image as ImageIcon, Plus, Trash2, Upload, FileImage } from 'lucide-react';
import { Property, PropertyStatus, PropertyType } from '../types';
import { formatBRLMask, parseBRLToFloat } from '../utils';

interface InputFieldProps {
  label: string;
  path: string;
  type?: 'text' | 'number' | 'date' | 'currency';
  prefix?: string;
  placeholder?: string;
  value: any;
  onChange: (path: string, value: any) => void;
}

const InputField = ({ label, path, type = 'text', prefix, placeholder, value, onChange }: InputFieldProps) => {
  const displayValue = type === 'currency' ? formatBRLMask(value) : (value === undefined || value === null ? '' : value);

  return (
    <div className="flex-1 min-w-[200px]">
      <label className="block text-[13px] font-bold text-slate-500 mb-2 uppercase tracking-wider">{label}</label>
      <div className="relative group">
        {prefix && (
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold text-sm z-10 pointer-events-none">
            {prefix}
          </span>
        )}
        <input 
          type={type === 'currency' ? 'text' : type} 
          placeholder={placeholder}
          className={`w-full bg-slate-800 text-slate-100 ${prefix ? 'pl-11' : 'px-4'} py-3.5 rounded-2xl border-none outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-xl placeholder:text-slate-500 font-medium`}
          value={displayValue}
          onChange={(e) => {
            const rawValue = e.target.value;
            if (type === 'currency') {
              const numeric = rawValue.replace(/\D/g, '');
              onChange(path, parseBRLToFloat(numeric));
            } else if (type === 'number') {
              const num = parseFloat(rawValue);
              onChange(path, isNaN(num) ? 0 : num);
            } else {
              onChange(path, rawValue);
            }
          }}
        />
      </div>
    </div>
  );
};

const PropertyForm = ({ properties, onSave }: { properties?: Property[], onSave: (p: Property) => void }) => {
  const navigate = useNavigate();
  const { id } = useParams();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Partial<Property>>({
    status: PropertyStatus.ARREMATADO,
    type: PropertyType.APARTAMENTO,
    acquisitionDate: new Date().toISOString().split('T')[0],
    acquisitionPrice: 0,
    auctioneerCommission: 0,
    sizeM2: 0,
    bankValuation: 0,
    legalEscritura: 0,
    legalItbi: 0,
    legalTaxasRegistro: 0,
    budgetReforma: 0,
    salePrice: 0,
    brokerage: 0,
    salesTax: 0,
    images: []
  });

  const [imageUrlInput, setImageUrlInput] = useState('');
  const [errors, setErrors] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    if (id && properties) {
      const existing = properties.find(p => p.id === id);
      if (existing) setFormData(existing);
    }
  }, [id, properties]);

  const handleChange = (path: string, value: any) => {
    setFormData(prev => ({ ...prev, [path]: value }));
  };

  const handleFileUpload = (files: FileList | null) => {
    if (!files) return;

    Array.from(files).forEach(file => {
      if (!file.type.startsWith('image/')) {
        alert('Por favor, selecione apenas arquivos de imagem.');
        return;
      }

      const reader = new FileReader();
      reader.onload = (e) => {
        const base64 = e.target?.result as string;
        setFormData(prev => ({
          ...prev,
          images: [...(prev.images || []), base64]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const addImageUrl = () => {
    if (!imageUrlInput) return;
    setFormData(prev => ({
      ...prev,
      images: [...(prev.images || []), imageUrlInput]
    }));
    setImageUrlInput('');
  };

  const removeImage = (index: number) => {
    setFormData(prev => ({
      ...prev,
      images: (prev.images || []).filter((_, i) => i !== index)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: string[] = [];

    if (!formData.neighborhood || formData.neighborhood.trim().length < 3) {
      newErrors.push('O Bairro/Condomínio deve ter pelo menos 3 caracteres.');
    }
    if (!formData.city || formData.city.trim().length < 2) {
      newErrors.push('A Cidade é obrigatória.');
    }
    if ((formData.acquisitionPrice || 0) <= 0) {
      newErrors.push('O Preço de Aquisição deve ser maior que zero.');
    }

    if (formData.status === PropertyStatus.VENDIDO) {
      if (!formData.legalItbi || !formData.legalTaxasRegistro) {
        newErrors.push('Status "Vendido" exige preenchimento de ITBI e Registro.');
      }
    }

    if (newErrors.length > 0) {
      setErrors(newErrors);
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    const finalData = {
      ...formData,
      id: formData.id || Math.random().toString(36).substr(2, 9),
      images: formData.images || []
    } as Property;

    onSave(finalData);
    navigate('/imoveis');
  };

  return (
    <div className="max-w-6xl mx-auto pb-20 animate-in fade-in duration-500">
      <div className="flex items-start justify-between mb-12">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight mb-2">
            {id ? 'Ficha do Ativo' : 'Novo Arremate'}
          </h2>
          <p className="text-slate-500 font-medium">Controle de engenharia, jurídico e comercial em um só lugar.</p>
        </div>
        <button 
          type="button"
          onClick={() => navigate(-1)}
          className="p-4 bg-white hover:bg-slate-50 text-slate-400 hover:text-slate-600 rounded-2xl transition-all border border-slate-200 shadow-sm"
        >
          <X size={24} />
        </button>
      </div>

      {errors.length > 0 && (
        <div className="mb-10 bg-rose-50 border-l-4 border-rose-500 p-6 rounded-r-3xl flex items-start space-x-4 shadow-xl">
          <AlertCircle className="text-rose-500 shrink-0 mt-0.5" size={24} />
          <div>
            <h4 className="text-rose-900 font-black text-sm uppercase tracking-wider mb-1">Pendências de Validação</h4>
            <ul className="list-disc list-inside text-rose-700 text-sm space-y-1">
              {errors.map((err, i) => <li key={i} className="font-medium">{err}</li>)}
            </ul>
          </div>
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-12">
        {/* GALERIA DE IMAGENS E UPLOAD */}
        <section className="bg-white p-10 rounded-[40px] border border-slate-200 shadow-sm space-y-10">
          <div className="flex items-center space-x-3 text-blue-600">
            <div className="p-2.5 bg-blue-50 rounded-2xl">
              <ImageIcon size={22} strokeWidth={2.5} />
            </div>
            <h3 className="font-black uppercase tracking-[0.2em] text-xs">Galeria de Fotos</h3>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
            {/* Zona de Upload Local */}
            <div 
              onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
              onDragLeave={() => setIsDragging(false)}
              onDrop={(e) => { e.preventDefault(); setIsDragging(false); handleFileUpload(e.dataTransfer.files); }}
              onClick={() => fileInputRef.current?.click()}
              className={`relative border-2 border-dashed rounded-[32px] p-12 transition-all cursor-pointer flex flex-col items-center justify-center text-center group ${
                isDragging ? 'border-blue-500 bg-blue-50 scale-[0.98]' : 'border-slate-200 hover:border-blue-400 hover:bg-slate-50'
              }`}
            >
              <input 
                type="file" 
                multiple 
                accept="image/*" 
                className="hidden" 
                ref={fileInputRef} 
                onChange={(e) => handleFileUpload(e.target.files)} 
              />
              <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                <Upload size={32} strokeWidth={2.5} />
              </div>
              <h4 className="text-lg font-black text-slate-900 mb-2">Upload do Computador</h4>
              <p className="text-sm text-slate-500 font-medium max-w-[250px]">
                Arraste suas fotos aqui ou <span className="text-blue-600 underline">clique para escolher</span> os arquivos.
              </p>
            </div>

            {/* Input de URL (Opcional) */}
            <div className="flex flex-col justify-center space-y-6">
              <div className="p-8 bg-slate-50 rounded-[32px] border border-slate-100">
                <label className="block text-[11px] font-black text-slate-400 uppercase tracking-widest mb-4">Ou Adicionar por URL</label>
                <div className="flex gap-4">
                  <input 
                    type="text" 
                    placeholder="Cole o link da imagem aqui..." 
                    className="flex-1 bg-white px-6 py-4 rounded-2xl border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium placeholder:text-slate-400"
                    value={imageUrlInput}
                    onChange={(e) => setImageUrlInput(e.target.value)}
                  />
                  <button 
                    type="button"
                    onClick={addImageUrl}
                    className="bg-slate-900 text-white px-6 rounded-2xl font-bold hover:bg-slate-800 transition-all flex items-center gap-2"
                  >
                    <Plus size={20} />
                  </button>
                </div>
              </div>
              <div className="flex items-center gap-4 text-slate-400 text-xs px-4">
                <FileImage size={16} />
                <p>Formatos suportados: JPG, PNG, WEBP. Máximo 2MB por arquivo recomendado.</p>
              </div>
            </div>
          </div>

          {/* Grid de Previsão */}
          <div className="pt-6">
            <h5 className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-6 px-2">Imagens Carregadas ({(formData.images || []).length})</h5>
            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6">
              {(formData.images || []).map((img, idx) => (
                <div key={idx} className="relative group aspect-square rounded-[24px] overflow-hidden border border-slate-200 shadow-lg bg-slate-100">
                  <img src={img} alt={`Imóvel ${idx}`} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-slate-900/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <button 
                      type="button"
                      onClick={() => removeImage(idx)}
                      className="p-3 bg-rose-600 text-white rounded-xl shadow-xl hover:scale-110 active:scale-95 transition-all"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </div>
              ))}
              {(formData.images || []).length === 0 && (
                <div className="col-span-full py-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-100 rounded-[32px] text-slate-300">
                  <ImageIcon size={48} strokeWidth={1} className="mb-4 opacity-20" />
                  <p className="text-sm font-bold italic">Nenhuma foto anexada ao ativo ainda.</p>
                </div>
              )}
            </div>
          </div>
        </section>

        {/* IDENTIFICAÇÃO E STATUS */}
        <section className="bg-white p-10 rounded-[40px] border border-slate-200 shadow-sm space-y-10">
          <div className="flex items-center space-x-3 text-blue-600">
            <div className="p-2.5 bg-blue-50 rounded-2xl">
              <Info size={22} strokeWidth={2.5} />
            </div>
            <h3 className="font-black uppercase tracking-[0.2em] text-xs">Informações Primárias</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="flex-1">
              <label className="block text-[13px] font-bold text-slate-500 mb-2 uppercase tracking-wider">Tipo de Ativo</label>
              <select 
                className="w-full bg-slate-800 text-slate-100 px-5 py-4 rounded-2xl border-none outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-xl font-medium appearance-none"
                value={formData.type}
                onChange={(e) => handleChange('type', e.target.value)}
              >
                {Object.values(PropertyType).map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
            <div className="flex-1">
              <label className="block text-[13px] font-bold text-slate-500 mb-2 uppercase tracking-wider">Status Operacional</label>
              <select 
                className="w-full bg-slate-800 text-slate-100 px-5 py-4 rounded-2xl border-none outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-xl font-medium appearance-none"
                value={formData.status}
                onChange={(e) => handleChange('status', e.target.value)}
              >
                {Object.values(PropertyStatus).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <InputField label="Cidade" path="city" type="text" placeholder="Ex: Rio de Janeiro" value={formData.city} onChange={handleChange} />
            <InputField label="Bairro ou Condomínio" path="neighborhood" type="text" placeholder="Ex: Barra da Tijuca" value={formData.neighborhood} onChange={handleChange} />
            <div className="md:col-span-2">
