            <h3 className="font-black uppercase tracking-[0.2em] text-xs">Custos Jurídicos</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
            <InputField label="Gasto Escritura" path="legalEscritura" type="currency" prefix="R$" value={formData.legalEscritura} onChange={handleChange} />
            <InputField label="Valor ITBI" path="legalItbi" type="currency" prefix="R$" value={formData.legalItbi} onChange={handleChange} />
            <InputField label="Emolumentos Registro" path="legalTaxasRegistro" type="currency" prefix="R$" value={formData.legalTaxasRegistro} onChange={handleChange} />
          </div>
