            <div className="flex items-center text-slate-400 font-bold uppercase tracking-widest text-xs">
              <MapPin size={14} className="mr-1.5" /> {property.city} • {property.type}
            </div>
          </div>
        </div>
        <button 
          onClick={() => navigate(`/imovel/${property.id}`)}
          className="flex items-center gap-2 text-slate-400 hover:text-slate-600 font-black text-xs uppercase tracking-widest"
        >
          Editar Ativo <ExternalLink size={14} />
