                    <div className="flex justify-between text-sm">
                      <span className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Comissão Leilão:</span>
                      <span className="font-black">{formatCurrency(property.auctioneerCommission)}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Área Privativa:</span>
                      <span className="font-black">{property.sizeM2} m²</span>
                    </div>
                    <div className="pt-6 border-t border-white/10 flex justify-between items-center">
                      <span className="text-blue-400 font-black text-xs uppercase tracking-widest">Total Alocado Inicial:</span>
                      <span className="text-2xl font-black text-blue-400">{formatCurrency(property.acquisitionPrice + property.auctioneerCommission)}</span>
                    </div>
                  </div>
                </div>
              </div>
