          {activeTab === 'despesas' && (
            <div className="space-y-8 animate-in slide-in-from-bottom-2">
              <div className="flex justify-between items-center">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Extrato de Lançamentos</h4>
                <button 
                  onClick={() => setIsExpenseModalOpen(true)}
                  className="bg-slate-900 text-white px-6 py-3 rounded-2xl text-[11px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-slate-800 transition-all shadow-xl"
