                  <Plus size={16} /> Novo Gasto
                </button>
              </div>
              <div className="overflow-hidden border border-slate-100 rounded-[24px]">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                    <tr>
                      <th className="py-6 px-8">Data</th>
                      <th className="py-6 px-8">Categoria</th>
                      <th className="py-6 px-8">Descrição</th>
                      <th className="py-6 px-8 text-right">Valor</th>
                      <th className="py-6 px-8"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {propertyExpenses.map((exp) => (
                      <tr key={exp.id} className="group hover:bg-slate-50 transition-colors">
                        <td className="py-6 px-8 text-xs font-bold text-slate-500">{new Date(exp.date).toLocaleDateString('pt-BR')}</td>
                        <td className="py-6 px-8">
                          <span className="text-[9px] font-black uppercase px-3 py-1 bg-slate-100 rounded-lg text-slate-500 tracking-widest">{exp.category}</span>
                        </td>
                        <td className="py-6 px-8 text-sm font-black text-slate-800 tracking-tight">{exp.description}</td>
                        <td className="py-6 px-8 text-base font-black text-slate-900 text-right">{formatCurrency(exp.amount)}</td>
                        <td className="py-6 px-8 text-right">
                          <button onClick={() => onDeleteExpense(exp.id)} className="p-3 text-slate-300 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all bg-white rounded-xl shadow-sm"><Trash2 size={16} /></button>
                        </td>
                      </tr>
                    ))}
                    {propertyExpenses.length === 0 && (
                      <tr>
                        <td colSpan={5} className="py-20 text-center text-slate-300 italic font-medium">Nenhum lançamento registrado neste imóvel.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'timeline' && (
            <div className="space-y-10 animate-in slide-in-from-bottom-2 max-w-3xl mx-auto">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] text-center mb-10">Rastro de Auditoria</h4>
              <div className="relative border-l-4 border-slate-100 ml-6 pl-12 space-y-12">
                {propertyLogs.map((log) => (
                  <div key={log.id} className="relative">
                    <div className="absolute -left-[60px] top-1 w-10 h-10 rounded-2xl bg-white border-4 border-slate-100 flex items-center justify-center shadow-lg">
                      <Clock size={16} className="text-slate-900" />
                    </div>
                    <div className="bg-slate-50 p-6 rounded-[24px] border border-slate-100">
                       <div className="flex items-center justify-between mb-3">
                          <span className="text-sm font-black text-slate-900 tracking-tight">{log.action}</span>
                          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{new Date(log.timestamp).toLocaleString('pt-BR')}</span>
                       </div>
                       <div className="flex items-center gap-4">
                          <div className="flex items-center text-[10px] text-slate-500 font-black uppercase tracking-widest bg-white px-3 py-1.5 rounded-xl border border-slate-100">
                             <User size={12} className="mr-2 text-blue-600" /> {log.userName}
                          </div>
                          {log.fromStatus && (
                            <div className="flex items-center text-[9px] font-black uppercase text-slate-400 tracking-widest">
                               {log.fromStatus} <ArrowRight size={10} className="mx-2" /> {log.toStatus}
                            </div>
                          )}
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Modal de Despesa com Máscara e Cores Corrigidas */}
      {isExpenseModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
          <form onSubmit={handleAddExpenseSubmit} className="bg-white rounded-[40px] shadow-2xl w-full max-w-lg p-12 animate-in zoom-in-95 duration-200">
