const AppContent = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => localStorage.getItem('master_auth') === 'true');
  const [currentUser] = useState<UserAccount>(INITIAL_MASTER);
  const [properties, setProperties] = useState<Property[]>(() => JSON.parse(localStorage.getItem('master_imoveis_data') || '[]'));
  const [expenses, setExpenses] = useState<Expense[]>(() => JSON.parse(localStorage.getItem('master_imoveis_expenses') || '[]'));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => JSON.parse(localStorage.getItem('master_imoveis_inventory') || '[]'));
  const [movements, setMovements] = useState<StockMovement[]>(() => JSON.parse(localStorage.getItem('master_imoveis_movements') || '[]'));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('master_imoveis_suppliers') || '[]'));
  const [warehouses, setWarehouses] = useState<Warehouse[]>(() => JSON.parse(localStorage.getItem('master_imoveis_warehouses') || '[]'));
  const [users, setUsers] = useState<UserAccount[]>(() => {
    const saved = localStorage.getItem('master_imoveis_users');
    if (saved) return JSON.parse(saved);
    return [INITIAL_MASTER];
  });
  const [teams, setTeams] = useState<Team[]>(() => JSON.parse(localStorage.getItem('master_imoveis_teams') || '[]'));
  const [logs, setLogs] = useState<PropertyLog[]>(() => JSON.parse(localStorage.getItem('master_imoveis_logs') || '[]'));

  const handleLogin = (success: boolean) => {
    if (success) {
      setIsAuthenticated(true);
      localStorage.setItem('master_auth', 'true');
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('master_auth');
  };

  const addLog = useCallback((log: Omit<PropertyLog, 'id' | 'timestamp' | 'userId' | 'userName'>) => {
    const newLog: PropertyLog = {
      ...log,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      userId: currentUser.id,
      userName: currentUser.name
    };
    setLogs(prev => [newLog, ...prev]);
  }, [currentUser]);

  const updatePropertyStatus = useCallback((propertyId: string, newStatus: PropertyStatus) => {
    const property = properties.find(p => p.id === propertyId);
    if (!property) return;

    const oldStatus = property.status;
    setProperties(prev => prev.map(p => p.id === propertyId ? { ...p, status: newStatus } : p));

    addLog({
      propertyId,
      action: `Status alterado de ${oldStatus} para ${newStatus}`,
      fromStatus: oldStatus,
      toStatus: newStatus
    });
  }, [properties, addLog]);

  const handleAddMovement = useCallback((mov: StockMovement) => {
    setMovements(prev => [mov, ...prev]);

    setInventory(prev => prev.map(item => {
      if (item.id === mov.itemId) {
        const change = mov.type === MovementType.ENTRADA_COMPRA ? mov.quantity : -mov.quantity;
        return { ...item, currentStock: item.currentStock + change };
      }
      return item;
    }));

    if (mov.type === MovementType.SAIDA_OBRA && mov.propertyId) {
      const item = inventory.find(i => i.id === mov.itemId);
      const newExpense: Expense = {
        id: `exp-auto-${mov.id}`,
        propertyId: mov.propertyId,
        category: ExpenseCategory.REFORMA,
        description: `Consumo Estoque: ${item?.name || 'Insumo'} (${mov.quantity} ${item?.unit || ''})`,
        amount: mov.totalPrice,
        date: mov.date,
        userId: currentUser.id,
        userName: currentUser.name,
        attachments: []
      };
      setExpenses(prev => [newExpense, ...prev]);
      addLog({
        propertyId: mov.propertyId,
        action: `Gasto de estoque registrado: ${newExpense.description}`
      });
    }
  }, [inventory, currentUser, addLog]);

  useEffect(() => {
    localStorage.setItem('master_imoveis_data', JSON.stringify(properties));
    localStorage.setItem('master_imoveis_expenses', JSON.stringify(expenses));
    localStorage.setItem('master_imoveis_inventory', JSON.stringify(inventory));
    localStorage.setItem('master_imoveis_movements', JSON.stringify(movements));
    localStorage.setItem('master_imoveis_suppliers', JSON.stringify(suppliers));
    localStorage.setItem('master_imoveis_warehouses', JSON.stringify(warehouses));
    localStorage.setItem('master_imoveis_users', JSON.stringify(users));
    localStorage.setItem('master_imoveis_teams', JSON.stringify(teams));
    localStorage.setItem('master_imoveis_logs', JSON.stringify(logs));
  }, [properties, expenses, inventory, movements, suppliers, warehouses, users, teams, logs]);

  if (!isAuthenticated) {
    return (
      <Routes>
        <Route path="/login" element={<LoginPage onLogin={handleLogin} />} />
        <Route path="*" element={<Navigate to="/login" />} />
      </Routes>
    );
  }

  return (
    <ProtectedLayout currentUser={currentUser} onLogout={handleLogout}>
      <Routes>
        <Route path="/" element={<Dashboard properties={properties} expenses={expenses} />} />
        <Route path="/imoveis" element={<PropertyList properties={properties} expenses={expenses} onUpdateStatus={updatePropertyStatus} />} />
        <Route path="/imovel/:id" element={<PropertyDetails properties={properties} expenses={expenses} logs={logs} onAddExpense={(e) => { setExpenses(prev => [e, ...prev]); addLog({ propertyId: e.propertyId, action: `Lançamento de despesa: ${e.description}` }); }} onDeleteExpense={(id) => setExpenses(prev => prev.filter(e => e.id !== id))} />} />
        <Route path="/novo" element={<PropertyForm properties={properties} onSave={(p) => { setProperties(prev => [...prev, p]); addLog({ propertyId: p.id, action: "Imóvel cadastrado" }); }} />} />
        <Route path="/estoque/insumos" element={<InsumosPage items={inventory} setItems={setInventory} />} />
        <Route path="/estoque/movimentos" element={<MovimentosPage movements={movements} items={inventory} suppliers={suppliers} properties={properties} onAddMovement={handleAddMovement} />} />
        <Route path="/estoque/fornecedores" element={<FornecedoresPage suppliers={suppliers} setSuppliers={setSuppliers} />} />
        <Route path="/estoque/almoxarifados" element={<AlmoxarifadosPage warehouses={warehouses} setWarehouses={setWarehouses} />} />
        <Route path="/relatorios" element={<ReportsPage properties={properties} expenses={expenses} inventory={inventory} />} />
        <Route path="/equipe" element={<TeamsPage currentUser={currentUser} users={users} setUsers={setUsers} teams={teams} setTeams={setTeams} />} />
        <Route path="/configuracoes" element={<SettingsPage />} />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </ProtectedLayout>
  );
};

const App = () => (
  <HashRouter>
    <AppContent />
  </HashRouter>
);

export default App;

