              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div><label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Qtd</label><input name="quantity" required type="number" step="0.01" className={inputClass} /></div>
                <div><label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Preço Unit.</label><input name="unitPrice" required type="number" step="0.01" className={inputClass} /></div>
              </div>
              <div><label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest mb-2 ml-1">Destinação (Opcional)</label><select name="propertyId" className={inputClass}><option value="">Estoque Master (Central)</option>{properties.map(p => <option key={p.id} value={p.id}>{p.neighborhood}</option>)}</select></div>
            </div>
            <div className="flex flex-col sm:flex-row gap-4 mt-12">
              <button type="button" onClick={() => setIsModalOpen(false)} className="order-2 sm:order-1 flex-1 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-slate-900 transition-colors">Cancelar</button>
              <button type="submit" className="order-1 sm:order-2 flex-1 py-4 bg-blue-600 text-white rounded-[24px] text-[10px] font-black uppercase tracking-widest shadow-2xl shadow-blue-500/30 hover:bg-blue-700 transition-all">Registrar Movimento</button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

