import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Building2, Lock, Mail, ArrowRight, ShieldCheck, AlertCircle, User, CheckCircle2 } from 'lucide-react';
import { supabase } from '../lib/supabase';

const SignUpPage = () => {
  const navigate = useNavigate();
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      // 1. Criar usuário no Auth
      const { data, error: signUpError } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: {
            full_name: name,
          },
        },
      });

      if (signUpError) throw signUpError;

      if (data.user) {
        // 2. Tentar inserir na tabela pública 'users'
        // Nota: Se houver um trigger no banco (SQL fornecido), isso pode ser redundante
        // mas o try-catch evita erros de duplicidade se o trigger já tiver rodado.
        try {
          await supabase.from('users').insert({
            id: data.user.id,
            name: name,
            email: email,
            role: 'Colaborador',
            active: true,
            permissions: {
              properties: ['view'],
              inventory: ['view'],
              finances: [],
              teams: [],
              reports: ['view']
            }
          });
        } catch (innerErr) {
          console.log('Trigger ou política RLS tratou a criação do perfil público.');
        }

        setSuccess(true);
      }
    } catch (err: any) {
      setError(err.message || 'Erro ao criar conta. Verifique se o e-mail já está em uso.');
      console.error('Sign up error:', err);
    } finally {
      setIsLoading(false);
    }
