const SidebarItem = ({ to, icon: Icon, label, active, visible = true, onClick }: { to?: string, icon: any, label: string, active: boolean, visible?: boolean, onClick?: () => void }) => {
  if (!visible) return null;
  const content = (
    <div className={`flex items-center space-x-3 p-3 rounded-xl transition-colors cursor-pointer ${
      active ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
    }`} onClick={onClick}>
      <Icon size={20} />
      <span className="font-medium flex-1">{label}</span>
    </div>
  );
  return to ? <Link to={to} onClick={onClick}>{content}</Link> : content;
};

const SidebarGroup = ({ label, icon: Icon, children, active, visible = true }: { label: string, icon: any, children?: React.ReactNode, active: boolean, visible?: boolean }) => {
  const [isOpen, setIsOpen] = useState(active);
  if (!visible) return null;
  return (
    <div className="space-y-1">
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className={`flex items-center space-x-3 p-3 rounded-xl transition-colors cursor-pointer ${
          active && !isOpen ? 'bg-blue-600/20 text-blue-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
        }`}
      >
        <Icon size={20} />
        <span className="font-medium flex-1">{label}</span>
        {isOpen ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
      </div>
      {isOpen && <div className="pl-11 space-y-1 animate-in slide-in-from-top-2 duration-200">{children}</div>}
    </div>
  );
};

