import { formatBRLMask, parseBRLToFloat, maskDateBR, formatDateBR, parseBRDateToISO } from '../utils';

interface InputFieldProps {
  label: string;
  path: string;
  type?: 'text' | 'number' | 'date' | 'currency';
  prefix?: string;
  placeholder?: string;
  value: any;
  onChange: (path: string, value: any) => void;
  fullWidth?: boolean;
}

const InputField = ({ label, path, type = 'text', prefix, placeholder, value, onChange, fullWidth }: InputFieldProps) => {
  // Para datas, usamos um estado de exibição DD/MM/AAAA
  const [dateDisplay, setDateDisplay] = useState('');

  useEffect(() => {
    if (type === 'date' && value) {
      setDateDisplay(formatDateBR(value));
    }
  }, [value, type]);

  const displayValue = type === 'currency' 
    ? formatBRLMask(value) 
    : type === 'date' 
      ? dateDisplay 
      : (value === undefined || value === null ? '' : value);

  return (
    <div className={`w-full ${fullWidth ? 'md:col-span-2 lg:col-span-3' : ''}`}>
      <label className="block text-[11px] font-black text-slate-500 mb-2 uppercase tracking-widest ml-1">{label}</label>
      <div className="relative group">
        {prefix && (
          <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 font-black text-sm z-10 pointer-events-none">
            {prefix}
          </span>
        )}
        <input 
          type="text" // Sempre text para forçar nossas máscaras customizadas
          placeholder={type === 'date' ? 'DD/MM/AAAA' : placeholder}
          className={`w-full bg-slate-50 text-slate-900 ${prefix ? 'pl-12' : 'px-5'} py-4 rounded-2xl border border-slate-200 outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-medium placeholder:text-slate-400`}
          value={displayValue}
          onChange={(e) => {
            const rawValue = e.target.value;
            if (type === 'currency') {
              const numeric = rawValue.replace(/\D/g, '');
              onChange(path, parseBRLToFloat(numeric));
            } else if (type === 'date') {
              const masked = maskDateBR(rawValue);
              setDateDisplay(masked);
              if (masked.length === 10) {
                const iso = parseBRDateToISO(masked);
                onChange(path, iso);
              }
            } else if (type === 'number') {
              const num = parseFloat(rawValue);
              onChange(path, isNaN(num) ? 0 : num);
            } else {
              onChange(path, rawValue);
            }
          }}
        />
        {type === 'date' && (
          <Calendar size={18} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" />
        )}
      </div>
    </div>
  );
};

const PropertyForm = ({ properties, onSave }: { properties?: Property[], onSave: (p: Property) => void }) => {
  const navigate = useNavigate();
  const { id } = useParams();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Partial<Property>>({
    status: PropertyStatus.ARREMATADO,
    type: PropertyType.APARTAMENTO,
    acquisitionDate: new Date().toISOString().split('T')[0],
    acquisitionPrice: 0,
    auctioneerCommission: 0,
    sizeM2: 0,
    bankValuation: 0,
    legalEscritura: 0,
    legalItbi: 0,
    legalTaxasRegistro: 0,
    budgetReforma: 0,
    salePrice: 0,
    brokerage: 0,
    salesTax: 0,
    images: []
  });

  const [imageUrlInput, setImageUrlInput] = useState('');
  const [errors, setErrors] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    if (id && properties) {
      const existing = properties.find(p => p.id === id);
      if (existing) setFormData(existing);
    }
  }, [id, properties]);

  const handleChange = (path: string, value: any) => {
    setFormData(prev => ({ ...prev, [path]: value }));
  };

  const handleFileUpload = (files: FileList | null) => {
    if (!files) return;
    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        const base64 = e.target?.result as string;
        setFormData(prev => ({ ...prev, images: [...(prev.images || []), base64] }));
      };
      reader.readAsDataURL(file);
    });
  };

  const addImageUrl = () => {
    if (!imageUrlInput) return;
    setFormData(prev => ({ ...prev, images: [...(prev.images || []), imageUrlInput] }));
    setImageUrlInput('');
  };

  const removeImage = (index: number) => {
    setFormData(prev => ({ ...prev, images: (prev.images || []).filter((_, i) => i !== index) }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: string[] = [];
    if (!formData.neighborhood || formData.neighborhood.trim().length < 2) newErrors.push('O Bairro/Condomínio é obrigatório.');
    if (!formData.city || formData.city.trim().length < 2) newErrors.push('A Cidade é obrigatória.');
    if ((formData.acquisitionPrice || 0) <= 0) newErrors.push('O Preço de Aquisição deve ser informado.');

    if (newErrors.length > 0) { 
      setErrors(newErrors); 
      window.scrollTo({ top: 0, behavior: 'smooth' }); 
      return; 
    }

    onSave({ 
      ...formData, 
      id: formData.id || Math.random().toString(36).substr(2, 9), 
      images: formData.images || [] 
    } as Property);
    navigate('/imoveis');
  };

  const selectClass = "w-full bg-slate-50 text-slate-900 px-5 py-4 rounded-2xl border border-slate-200 outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-medium appearance-none";

