import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  Cell, PieChart, Pie 
} from 'recharts';
import { FileDown, FileSpreadsheet, TrendingUp, DollarSign, Package, MapPin, Building2, ArrowRight } from 'lucide-react';
import { Property, Expense, InventoryItem, PropertyStatus } from '../types';
import { calculatePropertyMetrics, formatCurrency, formatDateBR } from '../utils';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

const ReportsPage = ({ properties, expenses, inventory }: { properties: Property[], expenses: Expense[], inventory: InventoryItem[] }) => {
  const metrics = useMemo(() => {
    const propertyData = properties.map(p => ({
      ...p,
      metrics: calculatePropertyMetrics(p, expenses)
    }));

    const totalInvested = propertyData.reduce((acc, p) => acc + p.metrics.totalInvested, 0);

    const roiByCity = Array.from(new Set(properties.map(p => p.city))).map(city => {
      const cityProps = propertyData.filter(p => p.city === city && p.status === PropertyStatus.VENDIDO);
      return {
        city,
        roi: cityProps.length > 0 ? cityProps.reduce((acc, p) => acc + p.metrics.roi, 0) / cityProps.length : 0
      };
    });

    const statusDist = Object.values(PropertyStatus).map(s => ({
      name: s,
      value: properties.filter(p => p.status === s).length
    }));

    return { totalInvested, roiByCity, statusDist, propertyData };
  }, [properties, expenses, inventory]);

  const downloadCSV = () => {
    const headers = ['Imovel', 'Cidade', 'Tipo', 'Data Aquisicao', 'Status', 'Total Investido', 'Lucro Realizado', 'ROI (%)'];
    const rows = metrics.propertyData.map(p => [
      `"${p.neighborhood}"`,
      `"${p.city}"`,
      `"${p.type}"`,
      formatDateBR(p.acquisitionDate),
      `"${p.status}"`,
      p.metrics.totalInvested.toFixed(2),
      p.metrics.realizedProfit.toFixed(2),
      p.metrics.roi.toFixed(2)
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    // Add BOM for Excel compatibility with UTF-8
    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `relatorio_master_ativos_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-500 pb-20">
