        </div>
        <div className="flex gap-4 w-full md:w-auto">
          <button 
            onClick={downloadCSV}
            className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-600 text-white px-6 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-500/20"
          >
            <FileSpreadsheet size={18} /> Exportar CSV
          </button>
