            <FileDown size={18} /> Exportar PDF
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-blue-600 p-8 rounded-[32px] text-white shadow-2xl shadow-blue-500/20">
          <div className="p-3 bg-white/10 rounded-xl w-fit mb-6">
            <DollarSign size={24} />
          </div>
          <p className="text-[10px] font-black uppercase opacity-60 tracking-[0.2em] mb-2">Total Imobilizado</p>
          <p className="text-3xl font-black tracking-tight">{formatCurrency(metrics.totalInvested)}</p>
        </div>
        <div className="bg-emerald-600 p-8 rounded-[32px] text-white shadow-2xl shadow-emerald-500/20">
          <div className="p-3 bg-white/10 rounded-xl w-fit mb-6">
            <TrendingUp size={24} />
          </div>
          <p className="text-[10px] font-black uppercase opacity-60 tracking-[0.2em] mb-2">ROI Médio Realizado</p>
          <p className="text-3xl font-black tracking-tight">28.4% <span className="text-sm font-bold opacity-60">Líquido</span></p>
        </div>
