                      {p.metrics.roi.toFixed(1)}%
                    </div>
                  </td>
                  <td className="px-10 py-6 text-right">
                    <a href={`#/imovel/${p.id}`} className="p-3 bg-white text-slate-300 hover:text-blue-600 rounded-xl shadow-sm border border-slate-100 inline-block transition-all hover:shadow-md">
                      <ArrowRight size={18} />
                    </a>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

