import { formatBRLMask, parseBRLToFloat, maskDateBR, formatDateBR, parseBRDateToISO } from '../utils';

interface InputFieldProps {
  label: string;
  path: string;
  type?: 'text' | 'number' | 'date' | 'currency';
  prefix?: string;
  placeholder?: string;
  value: any;
  onChange: (path: string, value: any) => void;
  fullWidth?: boolean;
}

const InputField = ({ label, path, type = 'text', prefix, placeholder, value, onChange, fullWidth }: InputFieldProps) => {
  const [dateDisplay, setDateDisplay] = useState('');

  useEffect(() => {
    if (type === 'date' && value) {
      setDateDisplay(formatDateBR(value));
    }
  }, [value, type]);

  const displayValue = type === 'currency' 
    ? formatBRLMask(value) 
    : type === 'date' 
      ? dateDisplay 
      : (value === undefined || value === null ? '' : value);

  return (
    <div className={`w-full ${fullWidth ? 'md:col-span-2 lg:col-span-3' : ''}`}>
      <label className="block text-[11px] font-black text-slate-500 mb-2 uppercase tracking-widest ml-1">{label}</label>
      <div className="relative group">
        {prefix && (
          <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 font-black text-sm z-10 pointer-events-none">
            {prefix}
          </span>
        )}
        <input 
          type="text" 
          placeholder={type === 'date' ? 'DD/MM/AAAA' : placeholder}
          className={`w-full bg-slate-50 text-slate-900 ${prefix ? 'pl-12' : 'px-5'} py-4 rounded-2xl border border-slate-200 outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all font-medium placeholder:text-slate-400`}
          value={displayValue}
          onChange={(e) => {
            const rawValue = e.target.value;
            if (type === 'currency') {
              const numeric = rawValue.replace(/\D/g, '');
              onChange(path, parseBRLToFloat(numeric));
            } else if (type === 'date') {
              const masked = maskDateBR(rawValue);
              setDateDisplay(masked);
              if (masked.length === 10) {
                const iso = parseBRDateToISO(masked);
                onChange(path, iso);
              }
            } else if (type === 'number') {
              const num = parseFloat(rawValue);
              onChange(path, isNaN(num) ? 0 : num);
            } else {
              onChange(path, rawValue);
            }
          }}
        />
        {type === 'date' && (
          <Calendar size={18} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" />
        )}
      </div>
    </div>
  );
};

