import ReportsPage from './pages/ReportsPage';
import TeamsPage from './pages/TeamsPage';
import LoginPage from './pages/LoginPage';
import SignUpPage from './pages/SignUpPage';
import { 
  Property, Expense, InventoryItem, StockMovement, Supplier, 
  Warehouse, UserAccount, UserRole, Team, PermissionModule, 
  PermissionAction, UserPermissions, PropertyStatus, PropertyLog, 
  MovementType, ExpenseCategory 
} from './types';

const INITIAL_PERMISSIONS: UserPermissions = {
  properties: ['view', 'edit', 'delete'],
  inventory: ['view', 'edit', 'delete'],
  finances: ['view', 'edit', 'delete'],
  teams: ['view', 'edit', 'delete'],
  reports: ['view', 'edit', 'delete']
};

const SidebarItem = ({ to, icon: Icon, label, active, visible = true, onClick }: { to?: string, icon: any, label: string, active: boolean, visible?: boolean, onClick?: () => void }) => {
  if (!visible) return null;
  const content = (
    <div className={`flex items-center space-x-3 p-3 rounded-xl transition-colors cursor-pointer ${
      active ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
    }`} onClick={onClick}>
      <Icon size={20} />
      <span className="font-medium flex-1">{label}</span>
    </div>
  );
  return to ? <Link to={to} onClick={onClick}>{content}</Link> : content;
};

const SidebarGroup = ({ label, icon: Icon, children, active, visible = true }: { label: string, icon: any, children?: React.ReactNode, active: boolean, visible?: boolean }) => {
  const [isOpen, setIsOpen] = useState(active);
  if (!visible) return null;
  return (
    <div className="space-y-1">
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className={`flex items-center space-x-3 p-3 rounded-xl transition-colors cursor-pointer ${
          active && !isOpen ? 'bg-blue-600/20 text-blue-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
        }`}
      >
        <Icon size={20} />
        <span className="font-medium flex-1">{label}</span>
        {isOpen ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
      </div>
      {isOpen && <div className="pl-11 space-y-1 animate-in slide-in-from-top-2 duration-200">{children}</div>}
    </div>
  );
};

const ProtectedLayout = ({ children, currentUser, onLogout }: { children?: React.ReactNode, currentUser: UserAccount, onLogout: () => void }) => {
  const location = useLocation();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const hasPermission = (module: PermissionModule, action: PermissionAction): boolean => {
    if (currentUser.role === UserRole.MASTER) return true;
    return currentUser.permissions?.[module]?.includes(action) || false;
  };

  const closeSidebar = () => setIsSidebarOpen(false);

  return (
    <div className="flex min-h-screen bg-slate-50 relative">
      {/* Mobile Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-30 lg:hidden"
          onClick={closeSidebar}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 w-72 bg-slate-900 text-white flex flex-col p-6 z-40 transition-transform duration-300 lg:translate-x-0 lg:static lg:h-screen lg:overflow-y-auto
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="flex items-center justify-between mb-10 px-2 group">
          <div className="flex items-center space-x-3">
            <div className="bg-blue-600 p-2.5 rounded-2xl group-hover:rotate-12 transition-transform"><Building2 size={24} /></div>
            <div>
              <h1 className="text-lg font-black leading-none">Master Imóveis</h1>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Portal ERP</span>
            </div>
          </div>
          <button className="lg:hidden p-2 text-slate-400" onClick={closeSidebar}>
            <CloseIcon size={24} />
          </button>
        </div>

        <nav className="flex-1 space-y-2 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-slate-800">
          <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} onClick={closeSidebar} />
          <div className="pt-6 pb-2 px-2 text-[10px] font-black text-slate-500 uppercase tracking-widest">Gestão Operacional</div>
          <SidebarItem to="/imoveis" icon={Home} label="Imóveis" active={location.pathname.startsWith('/imoveis')} visible={hasPermission('properties', 'view')} onClick={closeSidebar} />
          <SidebarGroup label="Estoque" icon={Box} active={location.pathname.startsWith('/estoque')} visible={hasPermission('inventory', 'view')}>
            <Link to="/estoque/insumos" onClick={closeSidebar} className={`block py-2 text-sm font-medium ${location.pathname === '/estoque/insumos' ? 'text-blue-500' : 'text-slate-500 hover:text-white'}`}>• Insumos</Link>
            <Link to="/estoque/movimentos" onClick={closeSidebar} className={`block py-2 text-sm font-medium ${location.pathname === '/estoque/movimentos' ? 'text-blue-500' : 'text-slate-500 hover:text-white'}`}>• Movimentos</Link>
            <Link to="/estoque/fornecedores" onClick={closeSidebar} className={`block py-2 text-sm font-medium ${location.pathname === '/estoque/fornecedores' ? 'text-blue-500' : 'text-slate-500 hover:text-white'}`}>• Fornecedores</Link>
          </SidebarGroup>
          <div className="pt-6 pb-2 px-2 text-[10px] font-black text-slate-500 uppercase tracking-widest">Estratégico</div>
          <SidebarItem to="/relatorios" icon={BarChart3} label="Relatórios" active={location.pathname === '/relatorios'} visible={hasPermission('reports', 'view')} onClick={closeSidebar} />
          <SidebarItem to="/equipe" icon={Users} label="Equipe" active={location.pathname === '/equipe'} visible={hasPermission('teams', 'view')} onClick={closeSidebar} />
        </nav>

        <div className="mt-auto pt-6 border-t border-slate-800 space-y-4">
          <div className="px-3 py-3.5 bg-slate-800/50 rounded-2xl text-xs font-bold uppercase truncate border border-slate-800">
            {currentUser.name}
          </div>
          <SidebarItem to="/configuracoes" icon={Settings} label="Ajustes" active={location.pathname === '/configuracoes'} onClick={closeSidebar} />
          <button onClick={onLogout} className="flex items-center space-x-3 p-3 w-full rounded-xl text-rose-400 hover:bg-rose-500/10 transition-colors">
            <LogOut size={20} /> <span className="font-medium">Sair</span>
          </button>
        </div>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col min-h-screen max-w-full overflow-hidden">
        {/* Mobile Header */}
        <header className="lg:hidden bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-20 shadow-sm">
          <div className="flex items-center space-x-3">
            <div className="bg-blue-600 p-1.5 rounded-lg text-white"><Building2 size={20} /></div>
            <span className="font-black text-slate-900 tracking-tight">Master Imóveis</span>
          </div>
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="p-2.5 bg-slate-50 rounded-xl text-slate-600 hover:bg-slate-100 transition-colors"
          >
            <Menu size={24} />
          </button>
        </header>

        <main className="flex-1 p-6 lg:p-10 overflow-x-hidden">
          <div className="max-w-7xl mx-auto">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

const AppContent = () => {
  const navigate = useNavigate();
  const [session, setSession] = useState<any>(null);
  const [isDemo, setIsDemo] = useState(localStorage.getItem('master_imoveis_demo') === 'true');
  const [loading, setLoading] = useState(true);

  const [properties, setProperties] = useState<Property[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [movements, setMovements] = useState<StockMovement[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [warehouses, setWarehouses] = useState<Warehouse[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [teams, setTeams] = useState<Team[]>([]);
  const [logs, setLogs] = useState<PropertyLog[]>([]);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
      if (session || isDemo) fetchData();
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchData();
    });

    return () => subscription.unsubscribe();
  }, [isDemo]);

  const fetchData = async () => {
    const fetchTable = async (table: string, setter: Function) => {
      const { data, error } = await supabase.from(table).select('*');
      if (!error) setter(data);
    };

    await Promise.all([
      fetchTable('properties', setProperties),
      fetchTable('expenses', setExpenses),
      fetchTable('inventory', setInventory),
      fetchTable('movements', setMovements),
      fetchTable('suppliers', setSuppliers),
      fetchTable('warehouses', setWarehouses),
      fetchTable('users', setUsers),
      fetchTable('teams', setTeams),
      fetchTable('logs', setLogs),
    ]);

    if (!isDemo) {
      const channel = supabase.channel('schema-db-changes')
        .on('postgres_changes', { event: '*', schema: 'public' }, () => {
          fetchData(); 
        })
        .subscribe();
      return () => { supabase.removeChannel(channel); };
    }
  };

  const currentUser: UserAccount = users.find(u => u.email === session?.user?.email) || {
    id: session?.user?.id || 'demo-user',
    name: session?.user?.user_metadata?.full_name || (isDemo ? 'Usuário Demo' : 'Usuário'),
    email: session?.user?.email || (isDemo ? 'demo@masterimoveis.com' : ''),
    role: UserRole.MASTER, 
    active: true,
    permissions: INITIAL_PERMISSIONS
  };

  const handleLogout = useCallback(async () => {
    if (isDemo) {
      localStorage.removeItem('master_imoveis_demo');
      setIsDemo(false);
    } else {
      await supabase.auth.signOut();
    }
    navigate('/login');
  }, [isDemo, navigate]);

  const addProperty = useCallback(async (p: Property) => {
    if (isDemo) {
      setProperties(prev => [...prev, p]);
      return;
    }
    const { error } = await supabase.from('properties').insert(p);
    if (!error) addLog({ propertyId: p.id, action: "Imóvel cadastrado via Supabase" });
  }, [isDemo]);

  const deleteProperty = useCallback(async (id: string) => {
    if (isDemo) {
      setProperties(prev => prev.filter(p => p.id !== id));
      setExpenses(prev => prev.filter(e => e.propertyId !== id));
      return;
    }
    const { error } = await supabase.from('properties').delete().eq('id', id);
    if (!error) {
      setProperties(prev => prev.filter(p => p.id !== id));
      setExpenses(prev => prev.filter(e => e.propertyId !== id));
    }
  }, [isDemo]);

  const updatePropertyStatus = useCallback(async (id: string, status: PropertyStatus) => {
    // Atualização Otimista para fluidez total no Kanban
    setProperties(prev => prev.map(p => p.id === id ? { ...p, status } : p));

    if (isDemo) return;

    const old = properties.find(p => p.id === id);
    const { error } = await supabase.from('properties').update({ status }).eq('id', id);
    if (!error) addLog({ propertyId: id, action: `Status alterado: ${old?.status} -> ${status}`, fromStatus: old?.status, toStatus: status });
  }, [isDemo, properties]);

  const addExpense = useCallback(async (e: Expense) => {
    if (isDemo) {
      setExpenses(prev => [...prev, e]);
      return;
    }
    const { error } = await supabase.from('expenses').insert(e);
    if (!error) addLog({ propertyId: e.propertyId, action: `Gasto lançado: ${e.description}` });
  }, [isDemo]);

  const addLog = async (log: Omit<PropertyLog, 'id' | 'timestamp' | 'userId' | 'userName'>) => {
    if (isDemo) return;
    await supabase.from('logs').insert({
      ...log,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      userId: currentUser.id,
      userName: currentUser.name
    });
  };

  const handleAddMovement = useCallback(async (mov: StockMovement) => {
    if (isDemo) {
      setMovements(prev => [...prev, mov]);
      return;
    }
    const { error } = await supabase.from('movements').insert(mov);
    if (error) return;

    const item = inventory.find(i => i.id === mov.itemId);
    if (item) {
      const change = mov.type === MovementType.ENTRADA_COMPRA ? mov.quantity : -mov.quantity;
      await supabase.from('inventory').update({ currentStock: item.currentStock + change }).eq('id', item.id);
    }
  }, [isDemo, inventory]);

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-slate-50">
      <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-6" />
      <div className="font-black text-slate-400 animate-pulse uppercase tracking-[0.2em] text-center">
        Sincronizando com Master Imóveis...
      </div>
    </div>
  );

  if (!session && !isDemo) {
    return (
      <Routes>
        <Route path="/login" element={<LoginPage onLogin={() => {}} />} />
        <Route path="/signup" element={<SignUpPage />} />
        <Route path="*" element={<Navigate to="/login" />} />
      </Routes>
    );
  }

  return (
    <ProtectedLayout currentUser={currentUser} onLogout={handleLogout}>
      <Routes>
        <Route path="/" element={<Dashboard properties={properties} expenses={expenses} />} />
        <Route path="/imoveis" element={<PropertyList properties={properties} expenses={expenses} onUpdateStatus={updatePropertyStatus} />} />
        <Route path="/imovel/:id" element={<PropertyDetails properties={properties} expenses={expenses} logs={logs} onAddExpense={addExpense} onDeleteExpense={async (id) => { if (isDemo) { setExpenses(expenses.filter(e => e.id !== id)); } else { await supabase.from('expenses').delete().eq('id', id); } }} onDeleteProperty={deleteProperty} />} />
        <Route path="/novo" element={<PropertyForm properties={properties} onSave={addProperty} />} />
        <Route path="/estoque/insumos" element={<InsumosPage items={inventory} setItems={setInventory} />} />
        <Route path="/estoque/movimentos" element={<MovimentosPage movements={movements} items={inventory} suppliers={suppliers} properties={properties} onAddMovement={handleAddMovement} />} />
        <Route path="/estoque/fornecedores" element={<FornecedoresPage suppliers={suppliers} setSuppliers={setSuppliers} />} />
        <Route path="/estoque/almoxarifados" element={<AlmoxarifadosPage warehouses={warehouses} setWarehouses={setWarehouses} />} />
        <Route path="/relatorios" element={<ReportsPage properties={properties} expenses={expenses} inventory={inventory} />} />
        <Route path="/equipe" element={<TeamsPage currentUser={currentUser} users={users} setUsers={setUsers} teams={teams} setTeams={setTeams} />} />
        <Route path="/configuracoes" element={<SettingsPage />} />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </ProtectedLayout>
  );
};

const App = () => (
  <HashRouter>
    <AppContent />
  </HashRouter>
);

export default App;

import React, { useState, useMemo, useCallback } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Search, MapPin, Building, ChevronRight, LayoutGrid, Kanban as KanbanIcon, ArrowRight, Image as ImageIcon, Plus } from 'lucide-react';
import { Property, PropertyStatus, Expense } from '../types';
import { formatCurrency, calculatePropertyMetrics } from '../utils';

// --- Interfaces para Props ---
interface PropertyCardProps {
  p: Property;
  expenses: Expense[];
  onClick: () => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
}

interface KanbanColumnProps {
  status: PropertyStatus;
  items: Property[];
  expenses: Expense[];
  onDrop: (id: string, status: PropertyStatus) => void;
  onDragStart: (e: React.DragEvent, id: string) => void;
  onNavigate: (id: string) => void;
}

interface PropertyListProps {
  properties: Property[];
  expenses: Expense[];
  onUpdateStatus: (id: string, status: PropertyStatus) => void;
}

// Memoizando o Card para evitar re-renders desnecessários durante o arraste
// Fix: Use an explicit interface for props to resolve type inference issues
const PropertyCard = React.memo(({ 
  p, 
  expenses, 
  onClick, 
  onDragStart 
}: PropertyCardProps) => {
  const metrics = useMemo(() => calculatePropertyMetrics(p, expenses), [p, expenses]);

  return (
    <div 
      draggable
      onDragStart={(e) => onDragStart(e, p.id)}
      onClick={onClick}
      className="bg-white rounded-3xl border border-slate-200 shadow-sm hover:shadow-xl hover:shadow-blue-500/10 hover:-translate-y-1 transition-all duration-200 cursor-grab active:cursor-grabbing overflow-hidden group touch-none"
    >
      <div className="h-24 md:h-28 overflow-hidden bg-slate-100 relative">
        {p.images && p.images.length > 0 ? (
          <img 
            src={p.images[0]} 
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" 
            alt="" 
            loading="lazy"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center text-slate-300">
            <ImageIcon size={20} />
          </div>
        )}
        <div className="absolute top-2 right-2">
          <div className="text-[8px] text-emerald-600 font-black bg-white/90 backdrop-blur px-2 py-0.5 rounded shadow-sm border border-emerald-100">
            {metrics.roi.toFixed(0)}% ROI
          </div>
        </div>
      </div>
      <div className="p-4">
        <h4 className="font-black text-slate-900 text-xs truncate mb-1 tracking-tight">{p.neighborhood}</h4>
        <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest flex items-center mb-3">
          <MapPin size={8} className="mr-1" /> {p.city}
        </p>
        <div className="flex justify-between items-center pt-3 border-t border-slate-50">
          <span className="text-[10px] font-black text-slate-900">{formatCurrency(metrics.totalInvested)}</span>
          <div className="p-1.5 bg-slate-50 rounded-lg text-slate-300 group-hover:text-blue-600 group-hover:bg-blue-50 transition-colors">
            <ChevronRight size={12} />
          </div>
        </div>
      </div>
    </div>
  );
});

// Fix: Use an explicit interface for props to resolve type inference issues
const KanbanColumn = ({ 
  status, 
  items, 
  expenses, 
  onDrop, 
  onDragStart,
  onNavigate 
}: KanbanColumnProps) => {
  const [isOver, setIsOver] = useState(false);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    if (!isOver) setIsOver(true);
  };

  const handleDragLeave = () => {
    setIsOver(false);
  };

  const handleDropLocal = (e: React.DragEvent) => {
    e.preventDefault();
    setIsOver(false);
    const id = e.dataTransfer.getData('propertyId');
    if (id) onDrop(id, status);
  };

  return (
    <div 
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDropLocal}
      className={`flex flex-col min-w-[280px] md:min-w-[320px] max-w-[360px] rounded-[32px] p-4 min-h-[600px] border-2 transition-all duration-200 ${
        isOver 
          ? 'bg-blue-50/50 border-blue-400 border-dashed scale-[1.01]' 
          : 'bg-slate-100/40 border-transparent'
      }`}
    >
      <div className="flex items-center justify-between mb-6 px-2">
        <div className="flex items-center gap-2">
           <div className={`w-2 h-2 rounded-full ${isOver ? 'bg-blue-500 animate-pulse' : 'bg-slate-300'}`} />
           <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">{status}</h3>
        </div>
        <span className="bg-white px-3 py-1 rounded-full text-[10px] font-black text-slate-900 shadow-sm border border-slate-100">{items.length}</span>
      </div>

      <div className="space-y-4 flex-1">
        {items.map(p => (
          <PropertyCard 
            key={p.id} 
            p={p} 
            expenses={expenses} 
            onDragStart={handleDragStart}
            onClick={() => onNavigate(p.id)}
          />
        ))}
        {items.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center py-20 text-slate-300 opacity-30 border-2 border-dashed border-slate-200 rounded-[24px]">
            <Building size={32} className="mb-2" />
            <p className="text-[9px] font-black uppercase tracking-widest">Arraste para cá</p>
          </div>
        )}
      </div>
    </div>
  );
};

// Fix: Use the defined PropertyListProps interface
const PropertyList = ({ properties, expenses, onUpdateStatus }: PropertyListProps) => {
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<'grid' | 'kanban'>('kanban');
  const [search, setSearch] = useState('');

  // Busca filtrada memoizada para performance
  const filteredProperties = useMemo(() => {
    if (!search) return properties;
    const s = search.toLowerCase();
    return properties.filter(p => 
      p.neighborhood.toLowerCase().includes(s) || 
      p.city.toLowerCase().includes(s)
    );
  }, [properties, search]);

  const handleDragStart = useCallback((e: React.DragEvent, propertyId: string) => {
    e.dataTransfer.setData('propertyId', propertyId);
    e.dataTransfer.effectAllowed = 'move';

    // Custom ghost preview logic could go here if needed, but native is faster
    if (e.currentTarget instanceof HTMLElement) {
       e.currentTarget.style.opacity = '0.5';
       setTimeout(() => {
         if (e.currentTarget instanceof HTMLElement) e.currentTarget.style.opacity = '1';
       }, 0);
    }
  }, []);

  const handleDrop = useCallback((id: string, status: PropertyStatus) => {
    onUpdateStatus(id, status);
  }, [onUpdateStatus]);

  const handleNavigate = useCallback((id: string) => {
    navigate(`/imovel/${id}`);
  }, [navigate]);

  return (
    <div className="space-y-8 animate-in fade-in duration-300">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl lg:text-4xl font-black text-slate-900 tracking-tight">Ativos Operacionais</h2>
          <p className="text-slate-500 font-medium">Controle de portfólio e pipeline de obras.</p>
        </div>
        <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4">
           <div className="bg-white border border-slate-200 rounded-[22px] p-1 flex shadow-sm order-2 sm:order-1">
              <button 
                onClick={() => setViewMode('kanban')}
                className={`flex-1 sm:flex-none p-2.5 px-6 rounded-2xl transition-all flex items-center justify-center gap-2 font-black text-[10px] uppercase tracking-widest ${viewMode === 'kanban' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <KanbanIcon size={16} /> <span className="sm:hidden lg:inline">Kanban</span>
              </button>
              <button 
                onClick={() => setViewMode('grid')}
                className={`flex-1 sm:flex-none p-2.5 px-6 rounded-2xl transition-all flex items-center justify-center gap-2 font-black text-[10px] uppercase tracking-widest ${viewMode === 'grid' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <LayoutGrid size={16} /> <span className="sm:hidden lg:inline">Grade</span>
              </button>
           </div>
           <Link to="/novo" className="bg-blue-600 text-white px-8 py-4 rounded-[24px] font-black hover:bg-blue-700 transition-all flex items-center justify-center space-x-3 shadow-2xl shadow-blue-500/20 order-1 sm:order-2 active:scale-95">
            <Plus size={20} strokeWidth={3} /> <span>Novo Ativo</span>
           </Link>
        </div>
      </div>

      <div className="bg-white p-4 rounded-[28px] border border-slate-200 shadow-sm">
