      p.neighborhood.toLowerCase().includes(s) || 
      p.city.toLowerCase().includes(s)
    );
  }, [properties, search]);

  const handleDragStart = useCallback((e: React.DragEvent, propertyId: string) => {
    e.dataTransfer.setData('propertyId', propertyId);
    e.dataTransfer.effectAllowed = 'move';

    // Custom ghost preview logic could go here if needed, but native is faster
    if (e.currentTarget instanceof HTMLElement) {
       e.currentTarget.style.opacity = '0.5';
       setTimeout(() => {
         if (e.currentTarget instanceof HTMLElement) e.currentTarget.style.opacity = '1';
       }, 0);
    }
  }, []);

