const AppContent = () => {
  const navigate = useNavigate();
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const [properties, setProperties] = useState<Property[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [movements, setMovements] = useState<StockMovement[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [warehouses, setWarehouses] = useState<Warehouse[]>([]);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [teams, setTeams] = useState<Team[]>([]);
  const [logs, setLogs] = useState<PropertyLog[]>([]);

  const fetchData = useCallback(async () => {
    const fetchTable = async (table: string, setter: Function) => {
      const { data, error } = await supabase.from(table).select('*');
      if (!error) setter(data);
    };
    await Promise.all([
      fetchTable('properties', setProperties),
      fetchTable('expenses', setExpenses),
      fetchTable('inventory', setInventory),
      fetchTable('movements', setMovements),
      fetchTable('suppliers', setSuppliers),
      fetchTable('warehouses', setWarehouses),
      fetchTable('users', setUsers),
      fetchTable('teams', setTeams),
      fetchTable('logs', setLogs),
    ]);
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session) {
      fetchData();
      const channel = supabase.channel('realtime-updates')
        .on('postgres_changes', { event: '*', schema: 'public' }, () => fetchData())
        .subscribe();
      return () => { supabase.removeChannel(channel); };
    }
  }, [session, fetchData]);

  const currentUser: UserAccount = users.find(u => u.email === session?.user?.email) || {
    id: session?.user?.id || 'loading',
    name: session?.user?.user_metadata?.full_name || 'Usuário',
    email: session?.user?.email || '',
    role: UserRole.MASTER, 
    active: true,
    permissions: INITIAL_PERMISSIONS
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    navigate('/login');
  };

  const addLog = async (log: Omit<PropertyLog, 'id' | 'timestamp' | 'userId' | 'userName'>) => {
    await supabase.from('logs').insert({
      ...log,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toISOString(),
      userId: currentUser.id,
      userName: currentUser.name
    });
  };

  const saveProperty = async (p: Property) => {
    const isEdit = properties.some(item => item.id === p.id);
    const oldProperties = [...properties];

    if (isEdit) {
      // ATUALIZAÇÃO OTIMISTA (Edição)
      setProperties(prev => prev.map(item => item.id === p.id ? p : item));
      const { error } = await supabase.from('properties').update(p).eq('id', p.id);
      if (error) {
        setProperties(oldProperties);
        console.error("Erro ao atualizar imóvel:", error);
      } else {
        addLog({ propertyId: p.id, action: "Informações do imóvel atualizadas" });
      }
    } else {
      // ATUALIZAÇÃO OTIMISTA (Criação)
      setProperties(prev => [p, ...prev]);
      const { error } = await supabase.from('properties').insert(p);
      if (error) {
        setProperties(oldProperties);
        console.error("Erro ao salvar imóvel:", error);
      } else {
        addLog({ propertyId: p.id, action: "Imóvel cadastrado no sistema" });
      }
    }
  };

  const updatePropertyStatus = async (id: string, status: PropertyStatus) => {
    const oldProps = [...properties];
    setProperties(prev => prev.map(p => p.id === id ? { ...p, status } : p));
    const { error } = await supabase.from('properties').update({ status }).eq('id', id);
    if (error) {
      setProperties(oldProps);
      console.error("Erro ao atualizar status:", error);
    } else {
      addLog({ propertyId: id, action: `Status alterado para ${status}` });
    }
  };

  const addExpense = async (e: Expense) => {
    setExpenses(prev => [...prev, e]);
    const { error } = await supabase.from('expenses').insert(e);
    if (error) {
      setExpenses(prev => prev.filter(item => item.id !== e.id));
    } else {
      addLog({ propertyId: e.propertyId, action: `Despesa lançada: ${e.description}` });
    }
  };

  const handleAddMovement = async (mov: StockMovement) => {
    setMovements(prev => [...prev, mov]);
    const { error } = await supabase.from('movements').insert(mov);
    if (error) {
      setMovements(prev => prev.filter(m => m.id !== mov.id));
    } else {
      const item = inventory.find(i => i.id === mov.itemId);
      if (item) {
        const change = mov.type === MovementType.ENTRADA_COMPRA ? mov.quantity : -mov.quantity;
        await supabase.from('inventory').update({ currentStock: item.currentStock + change }).eq('id', item.id);
        fetchData();
      }
    }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
      <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4" />
      <p className="font-black text-slate-400 uppercase tracking-widest text-xs">Conectando Master Imóveis...</p>
    </div>
  );

  if (!session) {
    return (
      <Routes>
        <Route path="/login" element={<LoginPage onLogin={() => {}} />} />
        <Route path="/signup" element={<SignUpPage />} />
        <Route path="*" element={<Navigate to="/login" />} />
      </Routes>
    );
  }

  return (
    <ProtectedLayout currentUser={currentUser} onLogout={handleLogout}>
      <Routes>
        <Route path="/" element={<Dashboard properties={properties} expenses={expenses} />} />
        <Route path="/imoveis" element={<PropertyList properties={properties} expenses={expenses} onUpdateStatus={updatePropertyStatus} />} />
        <Route path="/imovel/:id" element={<PropertyDetails properties={properties} expenses={expenses} logs={logs} onAddExpense={addExpense} onDeleteExpense={async (id) => { await supabase.from('expenses').delete().eq('id', id); fetchData(); }} />} />
        <Route path="/novo" element={<PropertyForm properties={properties} onSave={saveProperty} />} />
        <Route path="/editar/:id" element={<PropertyForm properties={properties} onSave={saveProperty} />} />
        <Route path="/estoque/insumos" element={<InsumosPage items={inventory} setItems={setInventory} />} />
        <Route path="/estoque/movimentos" element={<MovimentosPage movements={movements} items={inventory} suppliers={suppliers} properties={properties} onAddMovement={handleAddMovement} />} />
        <Route path="/estoque/fornecedores" element={<FornecedoresPage suppliers={suppliers} setSuppliers={setSuppliers} />} />
