/**
 * Função utilitária para acessar variáveis de ambiente de forma segura no navegador.
 * Evita o erro "ReferenceError: process is not defined" que causa a tela branca.
 */
const getEnv = (key: string, fallback: string): string => {
  try {
    // Verifica se 'process' e 'process.env' existem antes de acessar
    if (typeof process !== 'undefined' && process.env && process.env[key]) {
      return process.env[key] as string;
    }
  } catch (e) {
    // Silenciosamente falha e usa o fallback
  }
  return fallback;
};

